return ['domain'=>NULL,'plural-forms'=>'nplurals=1; plural=0;','language'=>'vi','project-id-version'=>'TranslatePress Multilingual','pot-creation-date'=>'2026-05-25T19:29:27+03:00','po-revision-date'=>'2026-05-25T19:29:27+03:00','x-generator'=>'TranslatePress build (community + OpenRouter), 2026-05-25','messages'=>['Please update the TranslatePress - Multilingual plugin to version %1$s or higher to ensure %2$s functions correctly.'=>'Vui lòng cập nhật plugin TranslatePress - Multilingual lên phiên bản %1$s trở lên để đảm bảo %2$s hoạt động chính xác.','Please install and activate the TranslatePress - Multilingual plugin'=>'Vui lòng cài đặt và kích hoạt plugin TranslatePress - Multilingual','Install & Activate'=>'Cài đặt & Kích hoạt','Please update TranslatePress - Multilingual to version %2$s or newer. Your currently installed version of TranslatePress - Multilingual is no longer compatible with the current version of %1$s.'=>'Vui lòng cập nhật TranslatePress - Multilingual lên phiên bản %2$s trở lên. Phiên bản TranslatePress - Multilingual hiện đã cài đặt của bạn không còn tương thích với phiên bản hiện tại của %1$s.','All TranslatePress functionalities are disabled until then.'=>'Tất cả các chức năng của TranslatePress sẽ bị vô hiệu hóa cho đến khi đó.','Update Now'=>'Cập nhật ngay','This TranslatePress add-on has been migrated to the main plugin and is no longer used. You can delete it.'=>'Tiện ích mở rộng TranslatePress này đã được chuyển sang plugin chính và không còn được sử dụng nữa. Bạn có thể xóa nó.','<strong>TranslatePress</strong> requires at least PHP version 5.6.20+ to run. It is the <a href="%s">minimum requirement of the latest WordPress version</a>. Please contact your server administrator to update your PHP version.'=>'<strong>TranslatePress</strong> yêu cầu ít nhất phiên bản PHP 5.6.20+ để chạy. Đây là <a href="%s">yêu cầu tối thiểu của phiên bản WordPress mới nhất</a>. Vui lòng liên hệ với quản trị viên máy chủ của bạn để cập nhật phiên bản PHP.','Advanced'=>'Nâng cao','Settings saved.'=>'Đã lưu cài đặt.','Are you sure you want to remove this item?'=>'Bạn có chắc chắn muốn xóa mục này không?','Remove'=>'Xóa','Add'=>'Thêm','Select...'=>'Chọn...','[%s] Low TranslatePress AI Words'=>'[%s] Số từ TranslatePress AI còn ít','upgrade your plan or get extra AI Words'=>'nâng cấp gói của bạn hoặc mua thêm từ AI','upgrade your plan'=>'nâng cấp gói của bạn','TranslatePress AI words are running low on your site.'=>'Số từ TranslatePress AI trên trang web của bạn sắp hết.','Current status: %s words remaining'=>'Trạng thái hiện tại: %s từ còn lại','Once the remaining AI words run out, automatic translation through TranslatePress AI will be paused.'=>'Khi số từ AI còn lại hết, tính năng dịch tự động qua TranslatePress AI sẽ bị tạm dừng.','To continue translating your content, please %1$s over at %2$s'=>'Để tiếp tục dịch nội dung của bạn, vui lòng %1$s tại %2$s','Manage Notification: %s'=>'Quản lý thông báo: %s','There is a new version of %1$s available. %2$sView version %3$s details%4$s or %5$supdate now%6$s.'=>'Đã có phiên bản mới của %1$s. %2$sXem chi tiết phiên bản %3$s%4$s hoặc %5$scập nhật ngay%6$s.','There is a new version of %1$s available. %2$sView version %3$s details%4$s.'=>'Đã có phiên bản mới của %1$s. %2$sXem chi tiết phiên bản %3$s%4$s.','To enable updates, please %1$senter your license key%2$s. Need a license key? %3$sPurchase one now%4$s.'=>'Để kích hoạt cập nhật, vui lòng %1$snhập khóa giấy phép của bạn%2$s. Cần khóa giấy phép? %3$sMua ngay%4$s.','To enable updates, please go to the %1$slicense page%2$s and check that you have a valid license.'=>'Để kích hoạt cập nhật, vui lòng truy cập %1$strang giấy phép%2$s và kiểm tra xem bạn có giấy phép hợp lệ hay không.','To enable updates, your licence needs to be renewed. Please go to the %1$sTranslatePress Account%2$s page and login to renew.'=>'Để kích hoạt cập nhật, giấy phép của bạn cần được gia hạn. Vui lòng truy cập trang %1$sTranslatePress Account%2$s và đăng nhập để gia hạn.','You do not have permission to install plugin updates'=>'Bạn không có quyền cài đặt cập nhật plugin','Error'=>'Lỗi','Your TranslatePress license key is invalid or missing.'=>'Khóa giấy phép TranslatePress của bạn không hợp lệ hoặc bị thiếu.','Your license key expired on %s.'=>'Khóa giấy phép của bạn đã hết hạn vào %s.','Your license key has been disabled.'=>'Khóa giấy phép của bạn đã bị vô hiệu hóa.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Khóa giấy phép của bạn đã bị vô hiệu hóa cho URL này. Kích hoạt lại từ <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Quản lý các trang.','<p><strong>License key mismatch.</strong> The license you entered doesn’t match the TranslatePress version you have installed.</p><p>Please check that you’ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Khóa giấy phép không khớp.</strong> Giấy phép bạn đã nhập không khớp với phiên bản TranslatePress bạn đã cài đặt.</p><p>Vui lòng kiểm tra rằng bạn đã cài đặt đúng phiên bản cho giấy phép của mình từ tài khoản TranslatePress của bạn.</p>','If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'Nếu bạn chỉ cài đặt plugin miễn phí nhưng đã thêm giấy phép trả phí, vui lòng cài đặt plugin trả phí từ tài khoản TranslatePress của bạn.','Your license key has reached its activation limit.'=>'Khóa giấy phép của bạn đã đạt đến giới hạn kích hoạt.','Upgrade your plan to add more sites. %1$sUpgrade now%2$s'=>'Nâng cấp gói của bạn để thêm nhiều trang web hơn. %1$sNâng cấp ngay%2$s','This website is already activated under a free license. Each website can only use one free license.'=>'Trang web này đã được kích hoạt bằng giấy phép miễn phí. Mỗi trang web chỉ có thể sử dụng một giấy phép miễn phí.','An error occurred, please try again.'=>'Đã xảy ra lỗi, vui lòng thử lại.','You have successfully activated your license'=>'Bạn đã kích hoạt giấy phép thành công','Others'=>'Khác','Restrict by Language'=>'Hạn chế theo ngôn ngữ','Exclude from Language'=>'Loại trừ khỏi ngôn ngữ','Restrict element to language'=>'Hạn chế phần tử theo ngôn ngữ','Show this element only in one language.'=>'Chỉ hiển thị phần tử này trong một ngôn ngữ.','Enable translation'=>'Bật dịch thuật','Allow translation to the corresponding language only if the content is written in the default language.'=>'Chỉ cho phép dịch sang ngôn ngữ tương ứng nếu nội dung được viết bằng ngôn ngữ mặc định.','Select language'=>'Chọn ngôn ngữ','Choose in which language to show this element.'=>'Chọn ngôn ngữ để hiển thị phần tử này.','Exclude element from language'=>'Loại trừ phần tử khỏi ngôn ngữ','Exclude this element from specific languages.'=>'Loại trừ phần tử này khỏi các ngôn ngữ cụ thể.','Select languages'=>'Chọn các ngôn ngữ','Choose from which languages to exclude this element.'=>'Chọn các ngôn ngữ để loại trừ phần tử này.','This element will still be visible when you are translating your website through the Translation Editor.'=>'Phần tử này vẫn sẽ hiển thị khi bạn đang dịch trang web thông qua Trình chỉnh sửa bản dịch.','The content of this element should be written in the default language.'=>'Nội dung của phần tử này nên được viết bằng ngôn ngữ mặc định.','<strong>TranslatePress</strong> encountered SQL errors. <a href="%s" title="View TranslatePress SQL Errors">Check out the errors</a>.'=>'<strong>TranslatePress</strong> đã gặp lỗi SQL. <a href="%s" title="Xem lỗi SQL của TranslatePress">Xem các lỗi</a>.','Automatic translation has been disabled.'=>'Dịch tự động đã bị tắt.','Dismiss this notice.'=>'Ẩn thông báo này.','Logged errors'=>'Lỗi đã ghi nhận','These are the most recent 5 errors logged by TranslatePress:'=>'Đây là 5 lỗi gần nhất được TranslatePress ghi nhận:','Yes'=>'Có','Why are these errors occuring'=>'Tại sao các lỗi này xảy ra','If TranslatePress detects something wrong when executing queries on your database, it may disable the Automatic Translation feature in order to avoid any extra charging by Google/DeepL. Automatic Translation needs to be manually turned on, after you solve the issues.'=>'Nếu TranslatePress phát hiện có lỗi khi thực thi truy vấn trên cơ sở dữ liệu của bạn, tính năng Dịch Tự động có thể bị vô hiệu hóa để tránh phát sinh thêm chi phí từ Google/DeepL. Bạn cần bật lại Dịch Tự động thủ công sau khi đã khắc phục các vấn đề.','The SQL errors detected can occur for various reasons including missing tables, missing permissions for the SQL user to create tables or perform other operations, problems after site migration or changes to SQL server configuration.'=>'Các lỗi SQL được phát hiện có thể xảy ra do nhiều nguyên nhân, bao gồm thiếu bảng, thiếu quyền của người dùng SQL để tạo bảng hoặc thực hiện các thao tác khác, sự cố sau khi di chuyển trang web hoặc thay đổi cấu hình máy chủ SQL.','What you can do in this situation'=>'Bạn có thể làm gì trong tình huống này','Plan A.'=>'Phương án A.','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL settings. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Vào Cài đặt -> TranslatePress -> thẻ Chung và Lưu cài đặt. Thao tác này sẽ tái tạo các bảng bằng cấu hình SQL hiện tại của bạn. Kiểm tra xem còn lỗi xảy ra khi duyệt trang web bằng ngôn ngữ đã dịch hay không. Xem mốc thời gian của các lỗi để đảm bảo bạn không nhìn thấy các lỗi cũ. Chỉ hiển thị 5 lỗi gần nhất.','Plan B.'=>'Phương án B.','If your problem isn\'t solved, try the following steps:'=>'Nếu vấn đề của bạn chưa được giải quyết, hãy thử các bước sau:','Create a backup of your database'=>'Tạo bản sao lưu cơ sở dữ liệu của bạn','Create a copy of each translation table where you encounter errors. You can copy the table within the same database (trp_dictionary_en_us_es_es_COPY for example) -- perform this step only if you want to keep the current translations'=>'Tạo bản sao của mỗi bảng dịch gặp lỗi. Bạn có thể sao chép bảng trong cùng cơ sở dữ liệu (ví dụ: trp_dictionary_en_us_es_es_COPY) -- chỉ thực hiện bước này nếu bạn muốn giữ các bản dịch hiện tại.','Remove the trouble tables by executing the DROP function on them'=>'Xóa các bảng gặp sự cố bằng cách thực thi hàm DROP trên chúng','Go to Settings -> TranslatePress -> General tab and Save Settings. This will regenerate the tables using your current SQL server.'=>'Vào Cài đặt -> TranslatePress -> thẻ Chung và Lưu cài đặt. Thao tác này sẽ tái tạo các bảng bằng máy chủ SQL hiện tại của bạn.','Copy the relevant content from the duplicated tables (trp_dictionary_en_us_es_es_COPY for example) in the newly generated table (trp_dictionary_en_us_es_es) -- perform this step only if you want to keep the current translations'=>'Sao chép nội dung liên quan từ các bảng đã sao chép (ví dụ: trp_dictionary_en_us_es_es_COPY) vào bảng mới được tạo (trp_dictionary_en_us_es_es) -- chỉ thực hiện bước này nếu bạn muốn giữ các bản dịch hiện tại.','Test it to see if everything is working. If something went wrong, you can restore the backup that you\'ve made at the first step. Check if no more errors occur while browsing your website in a translated language. Look at the timestamps of the errors to make sure you are not seeing the old errors. Only the most recent 5 errors are displayed.'=>'Kiểm tra để xem mọi thứ có hoạt động không. Nếu có sự cố, bạn có thể khôi phục bản sao lưu đã tạo ở bước đầu tiên. Kiểm tra xem còn lỗi xảy ra khi duyệt trang web bằng ngôn ngữ đã dịch hay không. Xem mốc thời gian của các lỗi để đảm bảo bạn không nhìn thấy các lỗi cũ. Chỉ hiển thị 5 lỗi gần nhất.','Plan C.'=>'Phương án C.','If your problem still isn\'t solved, try asking your hosting about your errors. The most common issue is missing permissions for the SQL user, such as the Create Tables permission.'=>'Nếu vấn đề của bạn vẫn chưa được giải quyết, hãy thử liên hệ với nhà cung cấp hosting về các lỗi này. Vấn đề phổ biến nhất là thiếu quyền cho người dùng SQL, chẳng hạn như quyền Tạo bảng (Create Tables).','Could not install. Try again from <a href="%s" >Plugins Dashboard.</a>'=>'Không thể cài đặt. Thử lại từ <a href="%s" >Bảng điều khiển Plugin.</a>','Active'=>'Đang hoạt động','Permission denied.'=>'Quyền truy cập bị từ chối.','Invalid nonce.'=>'Nonce không hợp lệ.','Settings scope unknown.'=>'Phạm vi cài đặt không xác định.','Legacy disabled.'=>'Chế độ cũ đã bị tắt.','Language Switcher'=>'Bộ chuyển đổi ngôn ngữ','Change language to %s'=>'Chuyển sang ngôn ngữ %s','Automatic Translation'=>'Dịch tự động','DeepL'=>'DeepL','Unsupported languages'=>'Ngôn ngữ không được hỗ trợ','The selected automatic translation engine does not provide support for these languages.<br>You can still manually translate pages in these languages using the Translation Editor.'=>'Công cụ dịch tự động đã chọn không hỗ trợ các ngôn ngữ này.<br>Bạn vẫn có thể dịch thủ công các trang sang các ngôn ngữ này bằng Trình chỉnh sửa bản dịch.','API key validation failed.'=>'Xác thực khóa API thất bại.','API key verification was successful.'=>'Xác thực khóa API thành công.','Please enter your Google Translate key.'=>'Vui lòng nhập khóa Google Translate của bạn.','Please enter your DeepL API key.'=>'Vui lòng nhập khóa API DeepL của bạn.','Not TranslatePress onboarding page.'=>'Không phải trang hướng dẫn TranslatePress.','Step %s does not exist'=>'Bước %s không tồn tại','Welcome'=>'Chào mừng','Add Languages'=>'Thêm ngôn ngữ','Enable Addons'=>'Bật tiện ích bổ sung','Finalize'=>'Hoàn tất','Exit Setup'=>'Thoát thiết lập','Upgrade'=>'Nâng cấp','Nothing here'=>'Không có gì ở đây','Your <strong>TranslatePress</strong> license is missing or invalid. <br/>Please %1$sregister your copy%2$s to enable automatic website translation via TranslatePress AI, premium addons, automatic updates and support. Need a license key? %3$sPurchase one now%4$s'=>'Giấy phép <strong>TranslatePress</strong> của bạn bị thiếu hoặc không hợp lệ. <br/>Vui lòng %1$sđăng ký bản sao của bạn%2$s để kích hoạt tính năng dịch tự động website qua TranslatePress AI, các tiện ích bổ sung cao cấp, cập nhật tự động và hỗ trợ. Cần khóa giấy phép? %3$sMua ngay%4$s','Your <strong>TranslatePress</strong> license will expire on %1$s. Please %2$sRenew Your Licence%3$s to continue receiving access to automatic translations via TP AI, premium addons, product downloads and automatic updates. %4$sRenew Now%5$s'=>'Giấy phép <strong>TranslatePress</strong> của bạn sẽ hết hạn vào %1$s. Vui lòng %2$sGia hạn Giấy phép%3$s để tiếp tục nhận quyền truy cập dịch tự động qua TP AI, các tiện ích bổ sung cao cấp, tải xuống sản phẩm và cập nhật tự động. %4$sGia hạn ngay%5$s','Error: '=>'Lỗi: ','Something went wrong, please try again.'=>'Đã xảy ra lỗi, vui lòng thử lại.','Your <strong>TranslatePress</strong> license has expired. <br/>Please %1$sRenew Your Licence%2$s to continue receiving access to automatic translations via TranslatePress AI, premium addons, product downloads, and automatic updates. %3$sRenew now %4$s'=>'Giấy phép <strong>TranslatePress</strong> của bạn đã hết hạn. <br/>Vui lòng %1$sGia hạn Giấy phép%2$s để tiếp tục nhận quyền truy cập dịch tự động qua TranslatePress AI, các tiện ích bổ sung cao cấp, tải xuống sản phẩm và cập nhật tự động. %3$sGia hạn ngay %4$s','License key mismatch. The license you entered doesn’t match the <strong>%1$s</strong> version you have installed. <br/>Please check that you’ve installed the correct version for your license from your %2$sTranslatePress account%3$s.'=>'Khóa giấy phép không khớp. Giấy phép bạn nhập không khớp với phiên bản <strong>%1$s</strong> bạn đã cài đặt. <br/>Vui lòng kiểm tra rằng bạn đã cài đặt đúng phiên bản cho giấy phép của mình từ %2$sTranslatePress Account%3$s của bạn.','<br/>If you have only the free plugin installed but added a paid license, please install the paid plugin from your TranslatePress account.'=>'<br/>Nếu bạn chỉ cài đặt plugin miễn phí nhưng đã thêm giấy phép trả phí, vui lòng cài đặt plugin trả phí từ TranslatePress Account của bạn.','You have reached the activation limit for your <strong>%1$s</strong> license. <br/>Manage your active sites from %2$s your account %3$s.'=>'Bạn đã đạt đến giới hạn kích hoạt cho giấy phép <strong>%1$s</strong> của bạn. <br/>Quản lý các trang web đang hoạt động của bạn từ %2$s tài khoản của bạn %3$s.','Your license is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Manage Sites.'=>'Giấy phép của bạn đã bị vô hiệu hóa cho URL này. Kích hoạt lại từ <a target="_blank" href="https://translatepress.com/account/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=license-deactivated">https://translatepress.com/account</a> -> Quản lý các trang web.','%1$s automatic translation requires an active license. Please %2$srenew%3$s your license or purchase a new one %4$shere%5$s.'=>'Dịch tự động %1$s yêu cầu giấy phép đang hoạt động. Vui lòng %2$sgia hạn%3$s giấy phép của bạn hoặc mua giấy phép mới %4$stại đây%5$s.','Please %1$senter%2$s your license key to enable %3$s automatic translation.'=>'Vui lòng %1$snhập%2$s khóa giấy phép của bạn để kích hoạt dịch tự động %3$s.','You have less than 5,000 TranslatePress AI words remaining. To continue automatically translating your website, please %spurchase additional AI words at a discount from your account%s.'=>'Bạn còn lại ít hơn 5.000 từ TranslatePress AI. Để tiếp tục dịch tự động website của bạn, vui lòng %smua thêm từ AI được giảm giá từ tài khoản của bạn%s.',' Error: '=>' Lỗi: ','This website is already activated under a free license. Each website can only use one free license. Please upgrade to a premium plan for more TranslatePress AI words from %1$s your account %2$s.'=>'Website này đã được kích hoạt bằng giấy phép miễn phí. Mỗi website chỉ có thể sử dụng một giấy phép miễn phí. Vui lòng nâng cấp lên gói trả phí để có thêm từ TranslatePress AI từ %1$s tài khoản của bạn %2$s.','You do not have a valid license for <strong>TranslatePress</strong>. %1$sGet one for free%2$s to get access to TranslatePress AI.'=>'Bạn không có giấy phép hợp lệ cho <strong>TranslatePress</strong>. %1$sNhận miễn phí%2$s để truy cập TranslatePress AI.','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. Upgrade to <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business or Developer</a> to access it + more premium perks!'=>'<strong>MỚI:</strong> Tiện ích bổ sung <strong>Different Domain per Language</strong> đã có mặt! Tăng cường SEO toàn cầu và tạo trải nghiệm địa phương với các tên miền theo quốc gia như .de hay .fr. Nâng cấp lên <a href="https://translatepress.com/pricing/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl-upsell" target="_blank">TranslatePress Business hoặc Developer</a> để truy cập tiện ích này cùng nhiều đặc quyền cao cấp khác!','<strong>NEW:</strong> The <strong>Different Domain per Language</strong> add-on is here! Boost your global SEO and create a local experience with country-specific domains like .de or .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Learn more</a>.'=>'<strong>MỚI:</strong> Tiện ích bổ sung <strong>Different Domain per Language</strong> đã có mặt! Tăng cường SEO toàn cầu và tạo trải nghiệm địa phương với các tên miền theo quốc gia như .de hay .fr. <a href="https://translatepress.com/docs/addons/different-domain-per-language/?utm_source=wp-dashboard&utm_medium=client-site&utm_campaign=new-addon-ddpl" target="_blank">Tìm hiểu thêm</a>.','The daily quota for machine translation characters exceeded. Please check the <strong>TranslatePress -> <a href="%s">Automatic Translation</a></strong> page for more information.'=>'Đã vượt quá hạn ngạch ký tự dịch máy hàng ngày. Vui lòng kiểm tra trang <strong>TranslatePress -> <a href="%s">Dịch Tự Động</a></strong> để biết thêm thông tin.','Marketing optin'=>'Đăng ký tiếp thị','Opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Chọn tham gia nhận thông báo cập nhật bảo mật và tính năng của chúng tôi, cùng với việc theo dõi chẩn đoán không nhạy cảm.','TranslatePress Preferred User Language'=>'Ngôn ngữ ưu tiên của người dùng TranslatePress','Preferred language to navigate the site'=>'Ngôn ngữ ưu tiên để duyệt trang web','The language is automatically set based by the last visited language by the user.'=>'Ngôn ngữ được tự động thiết lập dựa trên ngôn ngữ cuối cùng mà người dùng đã truy cập.','Always use this language'=>'Luôn sử dụng ngôn ngữ này','By checking this setting the preferred language will remain the one selected above, without the possibility of being changed in the frontend.<br>This language will be used in different operations such as sending email to the user.'=>'Khi bật cài đặt này, ngôn ngữ ưu tiên sẽ luôn là ngôn ngữ đã chọn ở trên, không thể thay đổi ở giao diện người dùng.<br>Ngôn ngữ này sẽ được sử dụng trong các thao tác khác nhau như gửi email cho người dùng.','Hello! Seems like you\'ve been using <strong>TranslatePress</strong> for a while now to translate your website. That\'s awesome! '=>'Xin chào! Có vẻ như bạn đã sử dụng <strong>TranslatePress</strong> được một thời gian để dịch trang web của mình. Thật tuyệt! ','If you can spare a few moments to rate it on WordPress.org it would help us a lot (and boost my motivation).'=>'Nếu bạn có thể dành vài phút để đánh giá trên WordPress.org, điều đó sẽ giúp ích cho chúng tôi rất nhiều (và tiếp thêm động lực cho tôi).','~ Razvan, developer of TranslatePress'=>'~ Razvan, nhà phát triển của TranslatePress','Rate TranslatePress on WordPress.org plugin page'=>'Đánh giá TranslatePress trên trang plugin WordPress.org','Ok, I will gladly help!'=>'Ok, tôi rất sẵn lòng giúp đỡ!','No, thanks.'=>'Không, cảm ơn.','Full Language Names'=>'Tên ngôn ngữ đầy đủ','Short Language Names'=>'Tên ngôn ngữ ngắn','Flags with Full Language Names'=>'Cờ kèm tên ngôn ngữ đầy đủ','Flags with Short Language Names'=>'Cờ kèm tên ngôn ngữ ngắn','Only Flags'=>'Chỉ cờ','Full Language Names No HTML'=>'Tên ngôn ngữ đầy đủ không HTML','Bottom Right'=>'Góc dưới bên phải','Bottom Left'=>'Góc dưới bên trái','Top Right'=>'Góc trên bên phải','Top Left'=>'Góc trên bên trái','Dark'=>'Tối','Light'=>'Sáng','Deactivate'=>'Hủy kích hoạt','Activate'=>'Kích hoạt','Invalid language code. Please try again.'=>'Mã ngôn ngữ không hợp lệ. Vui lòng thử lại.','Language codes can contain only A-Z a-z 0-9 - _ characters. Check your language codes in TranslatePress General Settings.'=>'Mã ngôn ngữ chỉ có thể chứa các ký tự A-Z a-z 0-9 - _. Kiểm tra mã ngôn ngữ của bạn trong mục Cài đặt chung của TranslatePress.','Error! Duplicate URL slug values.'=>'Lỗi! Các giá trị slug URL bị trùng lặp.','You cannot select two languages that have the same <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">iso code</a> but different formalities because doing so will lead to duplicate <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">hreflang tags</a>.'=>'Bạn không thể chọn hai ngôn ngữ có cùng <a href="https://en.wikipedia.org/wiki/List_of_ISO_639-1_codes" target="_blank">mã ISO</a> nhưng khác mức độ trang trọng vì làm như vậy sẽ dẫn đến <a href="https://developers.google.com/search/docs/specialty/international/localized-versions" target="_blank">thẻ hreflang</a> trùng lặp.','Duplicate language detected.<br>Each language can only be added once to ensure accurate translation management.<br> Please change the duplicate language entry and try again. '=>'Đã phát hiện ngôn ngữ trùng lặp.<br>Mỗi ngôn ngữ chỉ có thể được thêm một lần để đảm bảo quản lý bản dịch chính xác.<br> Vui lòng thay đổi mục ngôn ngữ trùng lặp và thử lại. ','Current Language'=>'Ngôn ngữ hiện tại','Opposite Language'=>'Ngôn ngữ ngược lại','General'=>'Chung','Translate Site'=>'Dịch trang web','Addons'=>'Tiện ích mở rộng','License'=>'Giấy phép','Settings'=>'Cài đặt','Activate License'=>'Kích hoạt giấy phép','Pro Features'=>'Tính năng Pro','Need Help?'=>'Cần trợ giúp?','Recent community discussions'=>'Thảo luận cộng đồng gần đây','Loading...'=>'Đang tải...','Unable to load forum posts'=>'Không thể tải các bài viết diễn đàn','Ask a Question'=>'Đặt câu hỏi','View All Topics'=>'Xem tất cả chủ đề','by'=>'bởi','Have a question?'=>'Bạn có câu hỏi?','Get help directly from the plugin developers, suggest improvements, or share your feedback!'=>'Nhận trợ giúp trực tiếp từ nhà phát triển plugin, đề xuất cải tiến hoặc chia sẻ phản hồi của bạn!','Tip for faster help:'=>'Mẹo để được trợ giúp nhanh hơn:','Include what you tried, what you expected, and what happened. Screenshots help!'=>'Nêu rõ những gì bạn đã thử, mong đợi và đã xảy ra. Ảnh chụp màn hình sẽ giúp ích!','Toggle support chat'=>'Bật/tắt hỗ trợ trò chuyện','Ask the community'=>'Hỏi cộng đồng','Close'=>'Đóng','Empty feed response'=>'Phản hồi nguồn cấp trống','Unable to parse feed'=>'Không thể phân tích nguồn cấp','Just now'=>'Vừa xong','%d hour ago'=>'%d giờ trước','%d day ago'=>'%d ngày trước','Source'=>'Nguồn','Srcset'=>'Srcset','Alt attribute'=>'Thuộc tính alt','Title attribute'=>'Thuộc tính title','Anchor link'=>'Liên kết neo','Placeholder attribute'=>'Thuộc tính placeholder','Submit attribute'=>'Thuộc tính submit','Text'=>'Văn bản','Video Poster'=>'Poster video','plural form'=>'Dạng số nhiều','one'=>'một','few'=>'một vài','many'=>'nhiều','other'=>'khác','Saved'=>'Đã lưu','Save'=>'Lưu','Saving translation...'=>'Đang lưu bản dịch...','You have unsaved changes!'=>'Bạn có thay đổi chưa lưu!','Discard changes'=>'Bỏ thay đổi','Discard All'=>'Bỏ tất cả','Loading Strings...'=>'Đang tải chuỗi...','Select string to translate...'=>'Chọn chuỗi để dịch...','Close Editor'=>'Đóng trình chỉnh sửa','From'=>'Từ','To'=>'Sang','Add Media'=>'Thêm tập tin','Other languages'=>'Ngôn ngữ khác','Context'=>'Ngữ cảnh','View Website As'=>'Xem trang web dưới dạng','Available in our Pro Versions'=>'Có sẵn trong các phiên bản Pro của chúng tôi','Select or Upload Media'=>'Chọn hoặc tải lên tập tin','Use this media'=>'Sử dụng tập tin này','Translate'=>'Dịch','Translate entire block element'=>'Dịch toàn bộ phần tử khối','Split block to translate strings individually'=>'Tách khối để dịch từng chuỗi riêng lẻ','Save changes to translation. Shortcut: CTRL(⌘) + S'=>'Lưu các thay đổi vào bản dịch. Phím tắt: CTRL(⌘) + S','Navigate to next string in dropdown list. Shortcut: CTRL(⌘) + ALT + Right Arrow'=>'Chuyển đến chuỗi tiếp theo trong danh sách thả xuống. Phím tắt: CTRL(⌘) + ALT + Mũi tên phải','Navigate to previous string in dropdown list. Shortcut: CTRL(⌘) + ALT + Left Arrow'=>'Chuyển đến chuỗi trước đó trong danh sách thả xuống. Phím tắt: CTRL(⌘) + ALT + Mũi tên trái','Discard all changes. Shortcut: CTRL(⌘) + ALT + Z'=>'Hủy bỏ tất cả các thay đổi. Phím tắt: CTRL(⌘) + ALT + Z','Discard changes to this text box. To discard changes to all text boxes use shortcut: CTRL(⌘) + ALT + Z'=>'Hủy bỏ các thay đổi đối với hộp văn bản này. Để hủy bỏ các thay đổi đối với tất cả các hộp văn bản, hãy dùng phím tắt: CTRL(⌘) + ALT + Z','Dismiss tooltip'=>'Bỏ qua chú thích','Quick Intro'=>'Giới thiệu nhanh','Are you sure you want to split this phrase into smaller parts?'=>'Bạn có chắc chắn muốn chia cụm từ này thành các phần nhỏ hơn không?','This string is not ready for translation yet. <br>Try again in a moment...'=>'Chuỗi này chưa sẵn sàng để dịch. <br>Hãy thử lại sau một lát...','For this option to work, please update the Browse as other role add-on to the latest version.'=>'Để tùy chọn này hoạt động, vui lòng cập nhật tiện ích bổ sung Duyệt với vai trò khác lên phiên bản mới nhất.','To translate slugs, please update the SEO Pack add-on to the latest version.'=>'Để dịch các slug, vui lòng cập nhật tiện ích bổ sung SEO Pack lên phiên bản mới nhất.','You can add a new language from <a href="%s">Settings->TranslatePress</a>'=>'Bạn có thể thêm ngôn ngữ mới từ <a href="%s">Cài đặt->TranslatePress</a>','However, you can still use TranslatePress to <strong style="background: #f5fb9d;">modify gettext strings</strong> available in your page.'=>'Tuy nhiên, bạn vẫn có thể sử dụng TranslatePress để <strong style="background: #f5fb9d;">sửa đổi các chuỗi gettext</strong> có trên trang của bạn.','Strings that are user-created cannot be modified, only those from themes and plugins.'=>'Các chuỗi do người dùng tạo không thể sửa đổi, chỉ những chuỗi từ giao diện và plugin.','Extra Translation Features'=>'Tính năng dịch thuật bổ sung','Support for 130+ Extra Languages'=>'Hỗ trợ hơn 130 ngôn ngữ bổ sung','Access to TranslatePress AI'=>'Truy cập TranslatePress AI','Translate SEO Title, Description, Slug'=>'Dịch Tiêu đề SEO, Mô tả, Slug','Publish only when translation is complete'=>'Chỉ xuất bản khi bản dịch đã hoàn tất','Translate by Browsing as User Role'=>'Dịch bằng cách duyệt với vai trò người dùng','Different Menu Items for each Language'=>'Các mục menu khác nhau cho mỗi ngôn ngữ','Automatic User Language Detection'=>'Tự động phát hiện ngôn ngữ người dùng','Upgrade to PRO'=>'Nâng cấp lên PRO','Upgrade to PRO with our biggest discount of the year!'=>'Nâng cấp lên PRO với mức giảm giá lớn nhất trong năm!','This Black Friday, get access to these features and more at a fraction of the costs:'=>'Trong dịp Black Friday này, hãy truy cập các tính năng này và hơn thế nữa với chi phí chỉ bằng một phần nhỏ:','No available suggestions'=>'Không có gợi ý khả dụng','Suggestions from translation memory'=>'Gợi ý từ bộ nhớ dịch','Click to Copy'=>'Nhấp để sao chép','Human Translation'=>'Bản dịch của con người','Machine Translation'=>'Bản dịch máy','Text on this page is %s% translated into all languages.'=>'Văn bản trên trang này được dịch %s% sang tất cả các ngôn ngữ.','%1$s% of text on this page is translated into %2$s.'=>'%1$s% văn bản trên trang này được dịch sang %2$s.','This page is %1$s% translated into %2$s.'=>'Trang này được dịch %1$s% sang %2$s.','The slug that you are trying to edit is present in other slug types:%s%. Editing it will replace each occurrence, regardless of the current type.'=>'Slug mà bạn đang cố gắng chỉnh sửa hiện có trong các loại slug khác:%s%. Việc chỉnh sửa sẽ thay thế mỗi lần xuất hiện, bất kể loại hiện tại.','Hover any text on the page, click %s,<br> then modify the translation in the sidebar.'=>'Di chuột qua bất kỳ văn bản nào trên trang, nhấp %s,<br> sau đó sửa đổi bản dịch trong thanh bên.','Don\'t forget to Save Translation. Use keyboard shortcut CTRL(⌘) + S'=>'Đừng quên lưu bản dịch. Sử dụng phím tắt CTRL(⌘) + S','Switch language to see the translation changes directly on the page.'=>'Chuyển đổi ngôn ngữ để xem các thay đổi bản dịch trực tiếp trên trang.','Search for any text in this page in the dropdown.'=>'Tìm kiếm bất kỳ văn bản nào trên trang này trong menu thả xuống.','Your %s license has <span class="trp-license-status-emphasized">expired</span>.'=>'Giấy phép %s của bạn đã <span class="trp-license-status-emphasized">hết hạn</span>.','Please renew your license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Vui lòng gia hạn giấy phép của bạn để tiếp tục nhận quyền truy cập vào TranslatePress AI, tiện ích bổ sung cao cấp, cập nhật tự động và hỗ trợ.','Renew Now'=>'Gia hạn ngay','<strong>This Black Friday, renew your license at a special price</strong> to continue receiving access to product downloads, automatic updates, and support.'=>'<strong>Trong dịp Black Friday này, gia hạn giấy phép của bạn với giá đặc biệt</strong> để tiếp tục nhận quyền truy cập tải xuống sản phẩm, cập nhật tự động và hỗ trợ.','Get Deal'=>'Nhận ưu đãi','Your %s license was <span class="trp-license-status-emphasized">refunded</span>.'=>'Giấy phép %s của bạn đã được <span class="trp-license-status-emphasized">hoàn tiền</span>.','Please purchase a new license to continue receiving access to TranslatePress AI, premium addons, automatic updates and support.'=>'Vui lòng mua giấy phép mới để tiếp tục nhận quyền truy cập vào TranslatePress AI, tiện ích bổ sung cao cấp, cập nhật tự động và hỗ trợ.','Purchase a new license'=>'Mua giấy phép mới','Your %s license is <span class="trp-license-status-emphasized">missing or invalid</span>.'=>'Giấy phép %s của bạn <span class="trp-license-status-emphasized">thiếu hoặc không hợp lệ</span>.','Please enter a valid license to get access to TranslatePress AI, premium addons, automatic updates and support. Need a license key? %1$sPurchase one now%2$s'=>'Vui lòng nhập giấy phép hợp lệ để truy cập TranslatePress AI, tiện ích bổ sung cao cấp, cập nhật tự động và hỗ trợ. Cần khóa giấy phép? %1$sMua ngay%2$s','Enter a valid license'=>'Nhập giấy phép hợp lệ','Slugs'=>'Slug','Meta Information'=>'Thông tin Meta','String List'=>'Danh sách chuỗi','Gettext Strings'=>'Chuỗi Gettext','Images'=>'Hình ảnh','Videos'=>'Video','Audios'=>'Âm thanh','Dynamically Added Strings'=>'Chuỗi được thêm động','Translation Editor'=>'Trình chỉnh sửa bản dịch','Edit translations by visually selecting them on each site page'=>'Chỉnh sửa bản dịch bằng cách chọn trực quan trên từng trang của website','String Translation'=>'Dịch chuỗi','Edit url slug translations, plugins and theme translation (emails, forms etc.)'=>'Chỉnh sửa bản dịch slug URL, plugin và giao diện (email, form v.v.)','Current User'=>'Người dùng hiện tại','Logged Out'=>'Đã đăng xuất','Translate Page'=>'Dịch trang','Add a New Language'=>'Thêm ngôn ngữ mới','Get a Free AI License'=>'Nhận giấy phép AI miễn phí','Your License is Invalid'=>'Giấy phép của bạn không hợp lệ','Get More AI Words (%d left)'=>'Nhận thêm từ AI (%d còn lại)','Opens post in the translation editor. Post must be saved as draft or published beforehand.'=>'Mở bài viết trong trình chỉnh sửa bản dịch. Bài viết phải được lưu dưới dạng bản nháp hoặc đã xuất bản trước đó.','Security check'=>'Kiểm tra bảo mật','<strong>Warning:</strong> Some strings have possibly incorrectly encoded characters. This may result in breaking the queries, rendering the page untranslated in live mode. Consider revising the following strings or their method of outputting.'=>'<strong>Cảnh báo:</strong> Một số chuỗi có thể chứa các ký tự được mã hóa không chính xác. Điều này có thể làm hỏng các truy vấn, khiến trang không được dịch ở chế độ trực tiếp. Hãy cân nhắc xem xét lại các chuỗi sau hoặc phương thức xuất của chúng.','TranslatePress data update'=>'Cập nhật dữ liệu TranslatePress','We need to update your translations database to the latest version.'=>'Chúng tôi cần cập nhật cơ sở dữ liệu bản dịch của bạn lên phiên bản mới nhất.','Updating will allow editing translations of localized text from plugins and theme. Existing translation will still work as expected.'=>'Việc cập nhật sẽ cho phép chỉnh sửa bản dịch của văn bản đã bản địa hóa từ plugin và theme. Bản dịch hiện có vẫn sẽ hoạt động như mong đợi.','IMPORTANT: It is strongly recommended to first backup the database!
Are you sure you want to continue?'=>'QUAN TRỌNG: Rất khuyến nghị sao lưu cơ sở dữ liệu trước!\\nBạn có chắc chắn muốn tiếp tục?','Run the updater'=>'Chạy trình cập nhật','Updating will allow editing translations of slugs. Existing translation will still work as expected.'=>'Việc cập nhật sẽ cho phép chỉnh sửa bản dịch của các đường dẫn tĩnh. Bản dịch hiện có vẫn sẽ hoạt động như mong đợi.','Please activate the SEO Addon from <br/>WordPress -> Settings -> TranslatePress -> Addons section'=>'Vui lòng kích hoạt SEO Addon từ <br/>WordPress -> Cài đặt -> TranslatePress -> mục Addons','Go to Addons'=>'Đến mục Addons','The SEO Pack add-on allows translation of all the URL slugs:'=>'Tiện ích bổ sung SEO Pack cho phép dịch tất cả các đường dẫn tĩnh URL:','Taxonomy slugs'=>'Đường dẫn tĩnh phân loại','Term slugs'=>'Đường dẫn tĩnh thuật ngữ','Post slugs (this includes pages and custom post types)'=>'Đường dẫn tĩnh bài viết (bao gồm cả trang và loại bài viết tùy chỉnh)','Post type base slugs'=>'Đường dẫn tĩnh cơ sở loại bài viết','WooCommerce slugs'=>'Đường dẫn tĩnh WooCommerce','The SEO Pack add-on is available with ALL premium versions of the plugin.'=>'Tiện ích mở rộng SEO Pack có sẵn trong TẤT CẢ các phiên bản trả phí của plugin.','Upgrade to Pro'=>'Nâng cấp lên Pro','Description'=>'Mô tả','Article Section'=>'Phần bài viết','Article Tag'=>'Thẻ bài viết','OG Title'=>'Tiêu đề OG','OG Site Name'=>'Tên trang OG','OG Description'=>'Mô tả OG','OG Image Alt'=>'Văn bản thay thế ảnh OG','Twitter Title'=>'Tiêu đề Twitter','Twitter Description'=>'Mô tả Twitter','Twitter Image Alt'=>'Văn bản thay thế ảnh Twitter','Page Title'=>'Tiêu đề trang','Dublin Core Title'=>'Tiêu đề Dublin Core','Dublin Core Description'=>'Mô tả Dublin Core','OG Image'=>'Ảnh OG','OG Image Secure URL'=>'URL bảo mật ảnh OG','Twitter Image'=>'Ảnh Twitter','Removing cdata dictionary strings for language %s...'=>'Đang xóa các chuỗi từ điển CDATA cho ngôn ngữ %s...','Removing untranslated dictionary links for language %s...'=>'Đang xóa liên kết từ điển chưa dịch cho ngôn ngữ %s...','Removing duplicated gettext strings for language %s...'=>'Đang xóa các chuỗi gettext trùng lặp cho ngôn ngữ %s...','Removing duplicated dictionary strings for language %s...'=>'Đang xóa các chuỗi từ điển trùng lặp cho ngôn ngữ %s...','Removing untranslated dictionary strings where translation is available for language %s...'=>'Đang xóa các chuỗi từ điển chưa được dịch khi bản dịch đã có sẵn cho ngôn ngữ %s...','Inserting original strings for language %s...'=>'Đang chèn các chuỗi gốc cho ngôn ngữ %s...','Cleaning original strings table for language %s...'=>'Đang dọn dẹp bảng chuỗi gốc cho ngôn ngữ %s...','Updating original string ids for language %s...'=>'Đang cập nhật ID chuỗi gốc cho ngôn ngữ %s...','Regenerating original meta table for language %s...'=>'Đang tạo lại bảng meta gốc cho ngôn ngữ %s...','Cleaning original meta table for language %s...'=>'Đang dọn dẹp bảng meta gốc cho ngôn ngữ %s...','Replacing original id NULL with value for language %s...'=>'Đang thay thế ID gốc NULL bằng giá trị cho ngôn ngữ %s...','Inserting gettext original strings for language %s...'=>'Đang chèn các chuỗi gốc gettext cho ngôn ngữ %s...','Cleaning gettext original strings table for language %s...'=>'Đang dọn dẹp bảng chuỗi gốc gettext cho ngôn ngữ %s...','Updating gettext original string ids for language %s...'=>'Đang cập nhật ID chuỗi gốc gettext cho ngôn ngữ %s...','Migrating taxonomy and post type base slugs to new table structure...'=>'Đang di chuyển các đường dẫn tĩnh phân loại và đường dẫn tĩnh cơ sở loại bài viết sang cấu trúc bảng mới...','Migrating post slugs to new table structure for language %s...'=>'Đang di chuyển các đường dẫn tĩnh bài viết sang cấu trúc bảng mới cho ngôn ngữ %s...','Migrating term slugs to new table structure for language %s...'=>'Đang di chuyển slug thuật ngữ sang cấu trúc bảng mới cho ngôn ngữ %s...','Finishing up...'=>'Đang hoàn tất...','Database optimization did not complete successfully. We recommend restoring the original database or <a href="%s" >trying again.</a>'=>'Tối ưu hóa cơ sở dữ liệu không thành công. Chúng tôi khuyên bạn nên khôi phục cơ sở dữ liệu gốc hoặc <a href="%s">thử lại.</a>','Update aborted! Your user account doesn\'t have the capability to perform database updates.'=>'Cập nhật bị hủy! Tài khoản của bạn không có quyền thực hiện cập nhật cơ sở dữ liệu.','Update aborted! Invalid nonce.'=>'Cập nhật bị hủy! Nonce không hợp lệ.','Update aborted! Incorrect action.'=>'Cập nhật bị hủy! Hành động không chính xác.','Update aborted! Incorrect language code.'=>'Cập nhật bị hủy! Mã ngôn ngữ không chính xác.','Updating database to version %s+'=>'Đang cập nhật cơ sở dữ liệu lên phiên bản %s+','Processing table for language %s...'=>'Đang xử lý bảng cho ngôn ngữ %s...','Back to TranslatePress Settings'=>'Quay lại Cài đặt TranslatePress','Successfully updated database!'=>'Đã cập nhật cơ sở dữ liệu thành công!',' done.'=>' xong.','All individual TranslatePress add-on plugins <a href="%1$s" target="_blank">have been discontinued</a> and are now included in the premium Personal, Business and Developer versions of TranslatePress. Please log into your <a href="%2$s" target="_blank">account page</a>, download the new premium version and install it. Your individual addons settings will be ported over.'=>'Tất cả các plugin tiện ích bổ sung TranslatePress riêng lẻ <a href="%1$s" target="_blank">đã ngừng cung cấp</a> và hiện được bao gồm trong các phiên bản trả phí Personal, Business và Developer của TranslatePress. Vui lòng đăng nhập vào <a href="%2$s" target="_blank">trang tài khoản</a> của bạn, tải xuống phiên bản trả phí mới và cài đặt. Các cài đặt tiện ích bổ sung riêng lẻ của bạn sẽ được chuyển sang.','Brand-new Language Switcher Settings are here!'=>'Cài đặt Bộ chuyển đổi ngôn ngữ hoàn toàn mới đã ra mắt!','Explore pre-made templates, switch colors, flag styles, spacing, layouts & more. Use the live preview to perfect your switcher in seconds.'=>'Khám phá các mẫu có sẵn, thay đổi màu sắc, kiểu cờ, khoảng cách, bố cục và hơn thế nữa. Sử dụng bản xem trước trực tiếp để hoàn thiện bộ chuyển đổi của bạn trong vài giây.','Start customizing'=>'Bắt đầu tùy chỉnh','Read documentation'=>'Đọc tài liệu','TranslatePress'=>'TranslatePress','<strong>TranslatePress</strong> requires <strong><a href="http://php.net/manual/en/book.mbstring.php">Multibyte String PHP library</a></strong>. Please contact your server administrator to install it on your server.'=>'<strong>TranslatePress</strong> yêu cầu <strong><a href="http://php.net/manual/en/book.mbstring.php">thư viện PHP xử lý chuỗi đa byte</a></strong>. Vui lòng liên hệ với quản trị viên máy chủ của bạn để cài đặt nó trên máy chủ.','Detected long query limitation on WPEngine hosting. Some large pages may appear untranslated. You can remove limitation by adding the following to your site’s wp-config.php: define( \'WPE_GOVERNOR\', false ); '=>'Đã phát hiện hạn chế truy vấn dài trên hosting WPEngine. Một số trang lớn có thể hiển thị chưa được dịch. Bạn có thể loại bỏ hạn chế bằng cách thêm dòng sau vào tệp wp-config.php của trang web: define( \'WPE_GOVERNOR\', false ); ','Custom Language Flag'=>'Cờ ngôn ngữ tùy chỉnh','The Language code of the added custom language cannot be empty.'=>'Mã ngôn ngữ của ngôn ngữ tùy chỉnh đã thêm không được để trống.','The Language code of the added custom language is invalid.'=>'Mã ngôn ngữ của ngôn ngữ tùy chỉnh đã thêm không hợp lệ.','The Automatic Translation Code of the added custom language is invalid.'=>'Mã dịch tự động của ngôn ngữ tùy chỉnh đã thêm không hợp lệ.','TranslatePress Add-ons'=>'Tiện ích bổ sung TranslatePress','You must first purchase this version to have access to the addon %1$shere%2$s'=>'Bạn phải mua phiên bản này trước để có quyền truy cập vào tiện ích bổ sung %1$stại đây%2$s','Please %1$senter your license%2$s key first, to activate this addon.'=>'Vui lòng %1$snhập khóa bản quyền%2$s của bạn trước để kích hoạt tiện ích bổ sung này.','You need an active license to have access to the addon. Renew or purchase a new one %1$shere%2$s.'=>'Bạn cần bản quyền đang hoạt động để truy cập tiện ích bổ sung. Gia hạn hoặc mua mới %1$stại đây%2$s.','Advanced Add-ons'=>'Tiện ích mở rộng nâng cao','These addons extend your translation plugin and are available in the Developer, Business and Personal plans.'=>'Các tiện ích bổ sung này mở rộng plugin dịch của bạn và có sẵn trong các gói Developer, Business và Personal.','SEO Pack'=>'SEO Pack','SEO Pack (Legacy)'=>'SEO Pack (Kế thừa)','SEO support for page slug, page title, description and facebook and twitter social graph information. The HTML lang attribute is properly set.'=>'Hỗ trợ SEO cho slug trang, tiêu đề trang, mô tả và thông tin đồ thị xã hội Facebook và Twitter. Thuộc tính lang HTML được thiết lập đúng cách.','Multiple Languages'=>'Nhiều ngôn ngữ','Add as many languages as you need for your project to go global. Publish your language only when all your translations are done.'=>'Thêm bao nhiêu ngôn ngữ tùy ý cho dự án của bạn để vươn ra toàn cầu. Chỉ xuất bản ngôn ngữ khi mọi bản dịch đã hoàn tất.','Pro Add-ons'=>'Tiện ích bổ sung Pro','These addons extend your translation plugin and are available in the Business and Developer plans.'=>'Các tiện ích bổ sung này mở rộng plugin dịch của bạn và có sẵn trong các gói Business và Developer.','DeepL Automatic Translation'=>'Dịch tự động DeepL','Automatically translate your website through the DeepL API.'=>'Tự động dịch trang web của bạn thông qua API DeepL.','Prompts visitors to switch to their preferred language based on their browser settings or IP address and remembers the last visited language.'=>'Gợi ý khách truy cập chuyển sang ngôn ngữ ưu tiên dựa trên cài đặt trình duyệt hoặc địa chỉ IP và ghi nhớ ngôn ngữ đã truy cập lần cuối.','Translator Accounts'=>'Tài khoản dịch giả','Create translator accounts for new users or allow existing users that are not administrators to translate your website.'=>'Tạo tài khoản dịch giả cho người dùng mới hoặc cho phép người dùng hiện tại không phải quản trị viên dịch trang web của bạn.','Browse As User Role'=>'Duyệt với tư cách vai trò người dùng','Navigate your website just like a particular user role would. Really useful for dynamic content or hidden content that appears for particular users.'=>'Điều hướng trang web của bạn như thể một vai trò người dùng cụ thể. Rất hữu ích cho nội dung động hoặc nội dung ẩn chỉ hiển thị với người dùng nhất định.','Navigation Based on Language'=>'Điều hướng dựa trên ngôn ngữ','Configure different menu items for different languages.'=>'Cấu hình các mục menu khác nhau cho từng ngôn ngữ.','Different Domain per Language'=>'Tên miền khác nhau cho mỗi ngôn ngữ','Connect separate domains or subdomains to each of your translated versions. Strengthen your brand’s local identity and boost SEO performance for every language you support.'=>'Kết nối các tên miền hoặc tên miền phụ riêng biệt với từng phiên bản đã dịch của bạn. Tăng cường bản sắc thương hiệu địa phương và cải thiện hiệu suất SEO cho mỗi ngôn ngữ bạn hỗ trợ.','Recommended Plugins'=>'Plugin đề xuất','A short list of plugins you can use to extend your website.'=>'Danh sách ngắn các plugin bạn có thể dùng để mở rộng trang web.','Profile Builder'=>'Profile Builder','Capture more user information on the registration form with the help of Profile Builder\'s custom user profile fields and/or add an Email Confirmation process to verify your customers accounts.'=>'Thu thập thêm thông tin người dùng trên biểu mẫu đăng ký với các trường hồ sơ người dùng tùy chỉnh của Profile Builder và/hoặc thêm quy trình Xác nhận Email để xác minh tài khoản khách hàng của bạn.','Paid Member Subscriptions'=>'Paid Member Subscriptions','Accept user payments, create subscription plans and restrict content on your membership site.'=>'Chấp nhận thanh toán của người dùng, tạo các gói đăng ký và hạn chế nội dung trên trang web thành viên của bạn.','WP Webhooks Automator'=>'WP Webhooks Automator','Create no-code automations and workflows on your WordPress site. Easily connect your plugins, sites and apps together.'=>'Tạo tự động hóa và quy trình làm việc không cần mã trên trang web WordPress của bạn. Dễ dàng kết nối các plugin, trang web và ứng dụng lại với nhau.','Save Changes'=>'Lưu thay đổi','TranslatePress Errors'=>'Lỗi TranslatePress','There are no logged errors.'=>'Không có lỗi nào được ghi lại.','Change language'=>'Thay đổi ngôn ngữ','Website language selector'=>'Bộ chọn ngôn ngữ trang web','WordPress Translation Plugin'=>'Plugin dịch WordPress','Available languages'=>'Ngôn ngữ có sẵn','Language Switcher update notice'=>'Thông báo cập nhật Bộ chuyển đổi ngôn ngữ','Legacy language switcher is currently enabled'=>'Bộ chuyển đổi ngôn ngữ cũ hiện đang được bật','We’ve upgraded the switcher for richer customization and a better user experience.<br>In order to use the new configurator, turn off <strong>Load legacy language switcher</strong>.'=>'Chúng tôi đã nâng cấp bộ chuyển đổi để có nhiều tùy chỉnh hơn và trải nghiệm người dùng tốt hơn.<br>Để sử dụng công cụ cấu hình mới, hãy tắt <strong>Tải bộ chuyển đổi ngôn ngữ cũ</strong>.','Note: You can switch back anytime from <strong>Advanced Settings → <a href="%s">Troubleshooting</a></strong>.'=>'Lưu ý: Bạn có thể chuyển lại bất cứ lúc nào từ <strong>Cài đặt nâng cao → <a href="%s">Khắc phục sự cố</a></strong>.','Enable the new switcher'=>'Bật bộ chuyển đổi mới','Your License Key is valid.'=>'Khóa giấy phép của bạn hợp lệ.','Your License Key is invalid.'=>'Khóa giấy phép của bạn không hợp lệ.','Your License has expired.'=>'Giấy phép của bạn đã hết hạn.','Deactivate License'=>'Hủy kích hoạt giấy phép','Add a license key'=>'Thêm khóa giấy phép','License Key'=>'Khóa giấy phép','Manage your license in your %1$s.'=>'Quản lý giấy phép của bạn trong %1$s.','Account Page'=>'Trang tài khoản','Don’t have a TranslatePress AI License Key?'=>'Bạn chưa có khóa giấy phép TranslatePress AI?','You can get one for %1$sfree%2$s, by creating a free account. It includes:'=>'Bạn có thể nhận một khóa %1$smiễn phí%2$s, bằng cách tạo một tài khoản miễn phí. Nó bao gồm:','Access to TranslatePress AI for instant automatic translations'=>'Quyền truy cập TranslatePress AI để dịch tự động ngay lập tức','2000 AI words to translate automatically'=>'2000 từ AI để dịch tự động','Get a free License Today'=>'Nhận giấy phép miễn phí ngay hôm nay','Debug Information'=>'Thông tin gỡ lỗi','Debug Data for License Checking'=>'Dữ liệu gỡ lỗi cho việc kiểm tra giấy phép','Debug Data for License Activation'=>'Dữ liệu gỡ lỗi cho việc kích hoạt giấy phép','Get more AI words and unlock all features with TranslatePress Pro.'=>'Nhận thêm từ AI và mở khóa mọi tính năng với TranslatePress Pro.','Upgrade now ↗'=>'Nâng cấp ngay ↗','Already purchased a Premium version?'=>'Đã mua phiên bản Premium chưa?','Go to your %1$s'=>'Truy cập %1$s của bạn','TranslatePress.com Account'=>'Tài khoản TranslatePress.com','Download & Install the Pro plugin'=>'Tải xuống và cài đặt plugin Pro','Learn More'=>'Tìm hiểu thêm','Get a translation volume estimate with a detailed breakdown per page'=>'Nhận ước tính khối lượng dịch với bảng phân tích chi tiết theo từng trang','Find how many translatable words are on your website'=>'Tìm số từ có thể dịch trên trang web của bạn','Enable Automatic Translation'=>'Kích hoạt dịch tự động','To use <strong>DeepL</strong> for automatic translation, activate this Pro add-on from the <a href="%1$s" target="_self" title="%2$s">%2$s</a>.'=>'Để sử dụng <strong>DeepL</strong> cho dịch tự động, hãy kích hoạt tiện ích bổ sung Pro này từ <a href="%1$s" target="_self" title="%2$s">%2$s</a>.','<strong>DeepL</strong> automatic translation is available as a <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.'=>'Dịch tự động <strong>DeepL</strong> có sẵn dưới dạng <a href="%1$s" target="_blank" title="%2$s">%2$s</a>.','By upgrading you\'ll get access to all paid add-ons, premium support and help fund the future development of TranslatePress.'=>'Bằng cách nâng cấp, bạn sẽ có quyền truy cập vào tất cả tiện ích bổ sung trả phí, hỗ trợ cao cấp và góp phần tài trợ cho sự phát triển trong tương lai của TranslatePress.','Please note that DeepL API usage is paid separately. See <a href="https://www.deepl.com/pro.html#developer">DeepL pricing information</a>.'=>'Vui lòng lưu ý rằng việc sử dụng API DeepL được tính phí riêng. Xem <a href="https://www.deepl.com/pro.html#developer">thông tin giá của DeepL</a>.','TranslatePress Pro Add-ons'=>'Tiện ích bổ sung TranslatePress Pro','Test API credentials'=>'Kiểm tra thông tin xác thực API','Check if the selected translation engine is configured correctly.'=>'Kiểm tra xem công cụ dịch đã chọn đã được cấu hình đúng chưa.','Alternative Engines'=>'Công cụ thay thế','Switch to TranslatePress AI'=>'Chuyển sang TranslatePress AI','Integrate machine translation directly with your WordPress website.'=>'Tích hợp dịch máy trực tiếp với trang web WordPress của bạn.','More info'=>'Thêm thông tin','Choose which engine you want to use in order to %1$s automatically translate your website.'=>'Chọn công cụ bạn muốn sử dụng để %1$s tự động dịch trang web của bạn.','Automatic Translation Settings'=>'Cài đặt Dịch tự động','AI Words Low Notification'=>'Thông báo Số từ AI Thấp','Receive an email notification when your TranslatePress AI word count drops below the specified threshold.'=>'Nhận thông báo qua email khi số từ AI TranslatePress của bạn giảm xuống dưới ngưỡng đã chỉ định.','This feature is only available when using the TranslatePress AI translation engine.'=>'Tính năng này chỉ khả dụng khi sử dụng công cụ dịch TranslatePress AI.','Notification Email'=>'Email thông báo','The email address where the low AI words notification will be sent.'=>'Địa chỉ email để gửi thông báo khi số từ AI thấp.','Word Threshold'=>'Ngưỡng Số từ','words'=>'từ','You will be notified when remaining AI words drop below this number.'=>'Bạn sẽ nhận được thông báo khi số từ AI còn lại giảm xuống dưới con số này.','Automatically Translate Slugs'=>'Tự động dịch các slug','Generate automatic translations of slugs for posts, pages and Custom Post Types.<br/>The slugs will be automatically translated starting with the second refresh of each page.'=>'Tạo bản dịch tự động cho slug của bài viết, trang và Custom Post Types.<br/>Các slug sẽ được dịch tự động bắt đầu từ lần làm mới thứ hai của mỗi trang.','This feature is only available in the paid version. Upgrade TranslatePress and unlock more premium features.'=>'Tính năng này chỉ khả dụng trong phiên bản trả phí. Nâng cấp TranslatePress và mở khóa thêm nhiều tính năng cao cấp.','Requires <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">SEO Pack Add-on</a> to be installed and activated.'=>'Yêu cầu cài đặt và kích hoạt <a href="%s" title="TranslatePress Add-on SEO Pack documentation" target="_blank">tiện ích bổ sung SEO Pack</a>.','Upgrade now'=>'Nâng cấp ngay','Block Crawlers'=>'Chặn Trình thu thập Dữ liệu','Block crawlers from triggering automatic translations on your website.<br>This will not prevent crawlers from accessing this site\'s pages.'=>'Chặn trình thu thập dữ liệu kích hoạt bản dịch tự động trên trang web của bạn.<br>Điều này sẽ không ngăn trình thu thập dữ liệu truy cập các trang của trang web này.','Limit machine translation / characters per day'=>'Giới hạn dịch máy / ký tự mỗi ngày','Add a limit to the number of automatically translated characters so you can better budget your project.'=>'Thêm giới hạn cho số lượng ký tự được dịch tự động để bạn có thể quản lý ngân sách dự án tốt hơn.','characters per day'=>'ký tự mỗi ngày','Today\'s Character Count: '=>'Số ký tự hôm nay: ','Log machine translation queries.'=>'Ghi log các truy vấn dịch máy.','Only enable for testing purposes. Can impact performance.<br>All records are stored in the wp_trp_machine_translation_log database table. Use a plugin like <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> to browse the logs or directly from your database manager (PHPMyAdmin, etc.)'=>'Chỉ bật cho mục đích thử nghiệm. Có thể ảnh hưởng đến hiệu suất.<br>Tất cả bản ghi được lưu trong bảng cơ sở dữ liệu wp_trp_machine_translation_log. Sử dụng plugin như <a href="https://wordpress.org/plugins/wp-data-access/" target="_blank">WP Data Access</a> để duyệt log hoặc trực tiếp từ trình quản lý cơ sở dữ liệu của bạn (PHPMyAdmin, v.v.)','Test API Credentials'=>'Kiểm tra thông tin xác thực API','HTTP Referrer: '=>'HTTP Referrer: ','Use this HTTP Referrer if the API lets you restrict key usage from its Dashboard.'=>'Sử dụng HTTP Referrer này nếu API cho phép bạn hạn chế việc sử dụng khóa từ Bảng điều khiển của nó.','Response'=>'Phản hồi','Response Body'=>'Nội dung phản hồi','Entire Response From wp_remote_get():'=>'Toàn bộ phản hồi từ wp_remote_get():','All Languages'=>'Tất cả ngôn ngữ','Select the languages you wish to make your website available in.'=>'Chọn các ngôn ngữ bạn muốn trang web của mình hỗ trợ.','Formality'=>'Mức độ trang trọng','Code'=>'Mã','Slug'=>'Slug','Default'=>'Mặc định','Formal'=>'Trang trọng','Informal'=>'Thân mật','Language'=>'Ngôn ngữ','This language does not support formality. '=>'Ngôn ngữ này không hỗ trợ mức độ trang trọng. ','Are you sure you want to remove this language?'=>'Bạn có chắc chắn muốn xóa ngôn ngữ này không?','Custom Languages'=>'Ngôn ngữ tùy chỉnh','To Add more languages activate the Multiple Languages Addon'=>'Để thêm nhiều ngôn ngữ hơn, hãy kích hoạt tiện ích bổ sung Multiple Languages','You need an active license to add more languages. Verify in your %1$saccount%2$s that your license is valid'=>'Bạn cần có giấy phép hoạt động để thêm nhiều ngôn ngữ hơn. Hãy xác minh trong %1$stài khoản%2$s của bạn rằng giấy phép vẫn còn hiệu lực.','Please %1$senter your license%2$s key first to add more languages.'=>'Vui lòng %1$snhập mã giấy phép%2$s của bạn trước để thêm nhiều ngôn ngữ hơn.','Adding more than two languages is a paid feature. Upgrade TranslatePress and unlock more premium features.'=>'Thêm nhiều hơn hai ngôn ngữ là tính năng trả phí. Hãy nâng cấp TranslatePress và mở khóa thêm các tính năng cao cấp.','Website Languages'=>'Ngôn ngữ trang web','Default Language'=>'Ngôn ngữ mặc định','Select the language your content is written in.'=>'Chọn ngôn ngữ mà nội dung của bạn được viết bằng.','WARNING. Changing the default language will invalidate existing translations.'=>'CẢNH BÁO. Thay đổi ngôn ngữ mặc định sẽ vô hiệu hóa các bản dịch hiện có.','Even changing from en_US to en_GB, because they are treated as two different languages.'=>'Ngay cả khi thay đổi từ en_US sang en_GB, vì chúng được coi là hai ngôn ngữ khác nhau.','In most cases changing the default flag is all it is needed: '=>'Trong hầu hết các trường hợp, chỉ cần thay đổi cờ mặc định là đủ: ','replace the default flag'=>'thay thế cờ mặc định','Re-run Setup Wizard'=>'Chạy lại Trình hướng dẫn Thiết lập','The Setup wizard allows you to quickly setup TranslatePress. You can initiate it at any time.'=>'Trình hướng dẫn Thiết lập cho phép bạn thiết lập TranslatePress nhanh chóng. Bạn có thể khởi chạy nó bất cứ lúc nào.','Language Settings'=>'Cài đặt Ngôn ngữ','Use Native language name'=>'Sử dụng tên ngôn ngữ bản địa','Check if you want to display languages in their native names. Otherwise, languages will be displayed in English.'=>'Chọn nếu bạn muốn hiển thị ngôn ngữ bằng tên bản địa của chúng. Nếu không, ngôn ngữ sẽ được hiển thị bằng tiếng Anh.','Use a subdirectory for the default language'=>'Sử dụng thư mục con cho ngôn ngữ mặc định','Check if you want to add the subdirectory in the URL for the default language.</br>By checking this option, the default language seen by website visitors will become the first one in the "All Languages" list.'=>'Chọn nếu bạn muốn thêm thư mục con vào URL cho ngôn ngữ mặc định.</br>Khi chọn tùy chọn này, ngôn ngữ mặc định mà khách truy cập trang web thấy sẽ trở thành ngôn ngữ đầu tiên trong danh sách "Tất cả ngôn ngữ".','Force language in custom links'=>'Buộc ngôn ngữ trong liên kết tùy chỉnh','Select Yes if you want to force custom links without language encoding to keep the currently selected language.'=>'Chọn Có nếu bạn muốn buộc các liên kết tùy chỉnh không có mã hóa ngôn ngữ vẫn giữ ngôn ngữ hiện đang được chọn.','Shortcode '=>'Shortcode ','Use shortcode on any page or widget.'=>'Sử dụng shortcode trên bất kỳ trang hoặc tiện ích nào.','You can also add the <a href="%s" title="Language Switcher Block Documentation">Language Switcher Block</a> in the WP Gutenberg Editor.'=>'Bạn cũng có thể thêm <a href="%s" title="Language Switcher Block Documentation">khối chuyển đổi ngôn ngữ</a> trong trình soạn thảo Gutenberg WP.','Menu item'=>'Mục menu','Go to  %1$s Appearance -> Menus%2$s to add languages to the Language Switcher in any menu.'=>'Vào  %1$sGiao diện -> Menu%2$s để thêm ngôn ngữ vào trình chuyển đổi ngôn ngữ trong bất kỳ menu nào.','Learn more in our documentation.'=>'Tìm hiểu thêm trong tài liệu của chúng tôi.','Floating language selection'=>'Lựa chọn ngôn ngữ nổi','Add a floating dropdown that follows the user on every page.'=>'Thêm một danh sách thả xuống nổi theo người dùng trên mọi trang.','Show "Powered by TranslatePress"'=>'Hiển thị "Powered by TranslatePress"','Show the small "Powered by TranslatePress" label in the floater language switcher.'=>'Hiển thị nhãn nhỏ "Powered by TranslatePress" trong trình chuyển đổi ngôn ngữ nổi.','5 Days to Better Multilingual Websites'=>'5 ngày để cải thiện trang web đa ngôn ngữ','%sJoin our FREE & EXCLUSIVE onboarding course%s and learn how to grow your multilingual traffic, reach international markets, and save time & money while getting the most out of TranslatePress!'=>'%sTham gia khóa học nhập môn MIỄN PHÍ & ĐỘC QUYỀN%s và tìm hiểu cách phát triển lưu lượng truy cập đa ngôn ngữ, tiếp cận thị trường quốc tế, đồng thời tiết kiệm thời gian & tiền bạc để tận dụng tối đa TranslatePress!','Invalid email address'=>'Địa chỉ email không hợp lệ','Your email'=>'Email của bạn','Sign me up!'=>'Đăng ký ngay!','Sign up with your email address and receive a 5-part email guide to help you maximize the power of TranslatePress.'=>'Đăng ký bằng địa chỉ email của bạn và nhận hướng dẫn qua email gồm 5 phần để giúp bạn tận dụng tối đa sức mạnh của TranslatePress.','Dismiss email course notification'=>'Bỏ qua thông báo khóa học email','Hey %s,<br>Never miss an important update - opt in to our security and feature updates notifications, and non-sensitive diagnostic tracking.'=>'Chào %s,<br>Đừng bao giờ bỏ lỡ cập nhật quan trọng - hãy đăng ký nhận thông báo cập nhật bảo mật và tính năng, cùng với việc theo dõi chẩn đoán không nhạy cảm.','Allow & Continue'=>'Cho phép & Tiếp tục','Skip'=>'Bỏ qua','This will allow TranslatePress to:'=>'Điều này sẽ cho phép TranslatePress:','Your profile overview'=>'Tổng quan hồ sơ của bạn','Name and email address'=>'Tên và địa chỉ email','Admin Notices'=>'Thông báo quản trị','Updates, announcements, marketing, no spam'=>'Cập nhật, thông báo, tiếp thị, không spam','Plugin status & settings'=>'Trạng thái & cài đặt plugin','Active, Deactivated, installed version and settings'=>'Đang hoạt động, Đã vô hiệu hóa, phiên bản đã cài đặt và các thiết lập','Privacy Policy'=>'Chính sách bảo mật','Terms of Service'=>'Điều khoản dịch vụ','Support'=>'Hỗ trợ','Documentation'=>'Tài liệu','Add Extra AI Words'=>'Thêm từ AI bổ sung','Optimize TranslatePress database tables'=>'Tối ưu hóa các bảng cơ sở dữ liệu TranslatePress','<strong>IMPORTANT NOTE:</strong> Before performing this action it is strongly recommended to first backup the database.'=>'<strong>LƯU Ý QUAN TRỌNG:</strong> Trước khi thực hiện thao tác này, rất khuyến nghị bạn sao lưu cơ sở dữ liệu trước.','IMPORTANT: It is strongly recommended to first backup the database!! Are you sure you want to continue?'=>'QUAN TRỌNG: Rất khuyến nghị bạn sao lưu cơ sở dữ liệu trước!! Bạn có chắc chắn muốn tiếp tục?','Operations to perform'=>'Các thao tác cần thực hiện','Remove CDATA for original and dictionary strings'=>'Xóa CDATA cho các chuỗi gốc và chuỗi từ điển','Removes CDATA from trp_original_strings and trp_dictionary_* tables.<br>This type of content should not be detected by TranslatePress. It might have been introduced in the database in older versions of the plugin.'=>'Xóa CDATA khỏi các bảng trp_original_strings và trp_dictionary_*.<br>Loại nội dung này không nên được phát hiện bởi TranslatePress. Nó có thể đã được thêm vào cơ sở dữ liệu trong các phiên bản cũ của plugin.','Remove untranslated links from dictionary tables'=>'Xóa liên kết chưa dịch khỏi các bảng từ điển','Removes untranslated links and images from all trp_dictionary_* tables. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Xóa các liên kết và hình ảnh chưa được dịch khỏi tất cả các bảng trp_dictionary_*. Các bảng này chứa bản dịch cho các chuỗi do người dùng nhập như nội dung bài viết, tiêu đề bài viết, menu, v.v.','Remove duplicate rows for gettext strings'=>'Xóa các hàng trùng lặp cho các chuỗi gettext','Cleans up all trp_gettext_* tables of duplicate rows. These tables contain translations for themes and plugin strings.'=>'Dọn dẹp tất cả các bảng trp_gettext_* khỏi các hàng trùng lặp. Các bảng này chứa bản dịch cho các chuỗi của theme và plugin.','Remove duplicate rows for dictionary strings'=>'Xóa các hàng trùng lặp cho các chuỗi từ điển','Cleans up all trp_dictionary_* tables of duplicate rows. These tables contain translations for user-inputted strings such as post content, post title, menus etc.'=>'Dọn dẹp tất cả các bảng trp_dictionary_* khỏi các hàng trùng lặp. Các bảng này chứa bản dịch cho các chuỗi do người dùng nhập như nội dung bài viết, tiêu đề bài viết, menu, v.v.','Remove duplicate rows for original dictionary strings'=>'Xóa các hàng trùng lặp cho các chuỗi từ điển gốc','Cleans up all trp_original_strings table of duplicate rows. This table contains strings in the default language, without any translation.<br>The trp_original_meta table, which contains meta information that refers to the post parent’s ID, is also regenerated.<br>Such duplicates can appear in exceptional situations of unexpected behavior.'=>'Dọn dẹp bảng trp_original_strings khỏi các hàng trùng lặp. Bảng này chứa các chuỗi bằng ngôn ngữ mặc định, không có bản dịch nào.<br>Bảng trp_original_meta, chứa thông tin meta tham chiếu đến ID của bài viết cha, cũng được tái tạo.<br>Các bản trùng lặp như vậy có thể xuất hiện trong các tình huống ngoại lệ do hành vi không mong muốn.','Replace gettext strings that have original ID NULL with the correct original IDs'=>'Thay thế các chuỗi gettext có ID gốc NULL bằng các ID gốc chính xác','Fixes an edge case issue where some gettext strings have the original ID incorrectly set to NULL, causing problems in the Translation Editor.<br>This operation corrects the original IDs in the trp_gettext_* tables.<br>Only check this option if you encountered an issue in the Translation Editor where clicking the green pencil did not bring up the gettext string for translation in the left sidebar.<br>Otherwise, please leave this option unchecked because it\'s an intensive operation.'=>'Sửa lỗi trường hợp hiếm gặp khi một số chuỗi gettext có ID gốc được đặt không chính xác thành NULL, gây ra sự cố trong Trình chỉnh sửa bản dịch.<br>Thao tác này sửa các ID gốc trong các bảng trp_gettext_*.<br>Chỉ chọn tùy chọn này nếu bạn gặp phải sự cố trong Trình chỉnh sửa bản dịch khi nhấp vào bút chì màu xanh lá không hiển thị chuỗi gettext để dịch trong thanh bên trái.<br>Nếu không, vui lòng để tùy chọn này không được chọn vì đây là thao tác nặng.','Optimize Database'=>'Tối ưu hóa cơ sở dữ liệu','TranslatePress Database Updater'=>'TranslatePress Database Updater','Updating TranslatePress tables. Please leave this window open.'=>'Đang cập nhật các bảng TranslatePress. Vui lòng để cửa sổ này mở.','The inactive languages will still be visible and active for the admin. For other users they won\'t be visible in the language switchers and won\'t be accessible either.'=>'Các ngôn ngữ không hoạt động vẫn sẽ hiển thị và hoạt động đối với quản trị viên. Đối với người dùng khác, chúng sẽ không hiển thị trong bộ chuyển đổi ngôn ngữ và cũng không thể truy cập được.','unknown'=>'không xác định','<strong>Extra Languages add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Tiện ích bổ sung Extra Languages</strong> yêu cầu TranslatePress phiên bản %1$s trở lên. Bạn hiện đang sử dụng phiên bản %2$s. Vui lòng cập nhật TranslatePress để kích hoạt tính năng này.','Automatic and manual slug translation changes performed when <strong>TranslatePress - Multilingual</strong> 2.8.4 was active had to be removed because of some issues with that version. All slug translations from before that version are now in use. Thank you for understanding!'=>'Các thay đổi dịch slug tự động và thủ công được thực hiện khi <strong>TranslatePress - Multilingual</strong> 2.8.4 đang hoạt động đã phải được xóa bỏ do một số sự cố với phiên bản đó. Tất cả các bản dịch slug từ trước phiên bản đó hiện đang được sử dụng. Cảm ơn bạn đã thông cảm!','If you absolutely need them, the removed translations can be found in tables trp_slug_original_obsolete and trp_slug_translation_obsolete.'=>'Nếu bạn thực sự cần chúng, các bản dịch đã xóa có thể được tìm thấy trong các bảng trp_slug_original_obsolete và trp_slug_translation_obsolete.','View Docs'=>'Xem tài liệu','Assign different domains or subdomains to each language. When visitors access these domains, TranslatePress loads the appropriate language translation directly without redirecting.'=>'Gán các tên miền hoặc tên miền phụ khác nhau cho mỗi ngôn ngữ. Khi khách truy cập các tên miền này, TranslatePress tải trực tiếp bản dịch ngôn ngữ phù hợp mà không chuyển hướng.','Example: %1$s for English, %2$s for Spanish, %3$s for French.'=>'Ví dụ: %1$s cho tiếng Anh, %2$s cho tiếng Tây Ban Nha, %3$s cho tiếng Pháp.','Before enabling:'=>'Trước khi bật:','Ensure your domains are registered, pointed to your server, and have SSL certificates configured.'=>'Đảm bảo các tên miền của bạn đã được đăng ký, trỏ đến máy chủ của bạn và đã cấu hình chứng chỉ SSL.','Domain'=>'Tên miền','Map this language to a different domain or sub-domain.'=>'Ánh xạ ngôn ngữ này sang một tên miền hoặc tên miền phụ khác.','https://example.com'=>'https://example.com','Prefill with current domain'=>'Điền sẵn tên miền hiện tại','Check DNS'=>'Kiểm tra DNS','Checking DNS...'=>'Đang kiểm tra DNS...','DNS is correctly configured!'=>'DNS đã được cấu hình chính xác!','DNS check failed. Please verify your domain configuration.'=>'Kiểm tra DNS thất bại. Vui lòng xác minh cấu hình tên miền của bạn.','This domain is already assigned to another language.'=>'Tên miền này đã được gán cho một ngôn ngữ khác.','<strong>Different Domain per Language add-on</strong> requires TranslatePress version %1$s or higher. You are currently using version %2$s. Please update TranslatePress to enable this feature.'=>'<strong>Tiện ích bổ sung Different Domain per Language</strong> yêu cầu TranslatePress phiên bản %1$s trở lên. Bạn hiện đang sử dụng phiên bản %2$s. Vui lòng cập nhật TranslatePress để kích hoạt tính năng này.','Note: This option is disabled when Different Domain for Language addon is active.'=>'Lưu ý: Tùy chọn này bị vô hiệu hóa khi tiện ích bổ sung Different Domain for Language đang hoạt động.','Different Domain per Language: Domain is required when domain mapping is enabled. The toggle has been disabled for languages with empty domains.'=>'Different Domain per Language: Tên miền là bắt buộc khi ánh xạ tên miền được bật. Nút chuyển đã bị vô hiệu hóa đối với các ngôn ngữ có tên miền trống.','Different Domain per Language: The same domain cannot be assigned to multiple languages. The toggle has been disabled for duplicate domains.'=>'Different Domain per Language: Không thể gán cùng một tên miền cho nhiều ngôn ngữ. Nút chuyển đã bị vô hiệu hóa đối với các tên miền trùng lặp.','Different Domain per Language: A language domain cannot be the same as the main site URL. The toggle has been disabled for the matching domain.'=>'Different Domain per Language: Tên miền ngôn ngữ không thể giống với URL trang web chính. Nút chuyển đã bị vô hiệu hóa đối với tên miền trùng khớp.','Please enter a domain.'=>'Vui lòng nhập một tên miền.','Invalid domain format.'=>'Định dạng tên miền không hợp lệ.','Could not reach domain: %s'=>'Không thể truy cập tên miền: %s','Domain returned HTTP status %d.'=>'Tên miền trả về mã trạng thái HTTP %d.','Domain is reachable!'=>'Tên miền có thể truy cập được!','Limit this menu item to the following languages'=>'Giới hạn mục menu này cho các ngôn ngữ sau','Date format'=>'Định dạng ngày tháng','Customize the date formatting per each translated language.<br/>Leave empty for default WP setting or see more information <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">here</a>'=>'Tùy chỉnh định dạng ngày tháng cho từng ngôn ngữ đã dịch.<br/>Để trống để dùng thiết lập mặc định của WP hoặc xem thêm thông tin <a href="https://wordpress.org/support/article/formatting-date-and-time/" title="Formatting Date and Time" target="_blank">tại đây</a>','To edit an existing TranslatePress language, input the language code and fill in only the columns you want to overwrite (e.g. Language name, Flag).<br>You can also add new custom languages. They will be available under General settings, All Languages list, where the URL slug can be edited.'=>'Để chỉnh sửa một ngôn ngữ TranslatePress hiện có, hãy nhập mã ngôn ngữ và điền vào chỉ các cột bạn muốn ghi đè (ví dụ: Tên ngôn ngữ, Cờ).<br>Bạn cũng có thể thêm các ngôn ngữ tùy chỉnh mới. Chúng sẽ có sẵn trong phần Cài đặt chung, danh sách Tất cả ngôn ngữ, nơi slug URL có thể được chỉnh sửa.','For custom flag, first upload the image in media library then paste the URL.<br>Changing or deleting a custom language will impact translations and site URL\'s.<br>The Language code and the ISO Code should contain only alphabetical values, numerical values, "-" and "_".<br>The ISO Codes can be found on <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> and <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.'=>'Đối với cờ tùy chỉnh, trước tiên hãy tải hình ảnh lên thư viện media sau đó dán URL.<br>Việc thay đổi hoặc xóa một ngôn ngữ tùy chỉnh sẽ ảnh hưởng đến các bản dịch và URL của trang web.<br>Mã ngôn ngữ và Mã ISO chỉ được chứa các ký tự chữ cái, ký tự số, "-" và "_".<br>Các Mã ISO có thể tìm thấy tại <a href = "https://cloud.google.com/translate/docs/languages" target = "_blank">Google ISO Codes</a> và <a href = "https://www.deepl.com/docs-api/translating-text/" target = "_blank">DeepL Target Codes</a>.','Language code'=>'Mã ngôn ngữ','Language name'=>'Tên ngôn ngữ','Native name'=>'Tên bản địa','ISO Code'=>'Mã ISO','Flag URL'=>'URL cờ','Text RTL'=>'Văn bản RTL','Custom language'=>'Ngôn ngữ tùy chỉnh','Disable dynamic translation'=>'Tắt dịch động','It disables detection of strings displayed dynamically using JavaScript. <br/>Strings loaded via a server side AJAX call will still be translated.'=>'Nó vô hiệu hóa việc phát hiện các chuỗi được hiển thị động bằng JavaScript. <br/>Các chuỗi được tải qua lệnh gọi AJAX phía máy chủ vẫn sẽ được dịch.','Disable translation for gettext strings'=>'Vô hiệu hóa dịch cho các chuỗi gettext','Gettext Strings are strings outputted by themes and plugins. <br> Translating these types of strings through TranslatePress can be unnecessary if they are already translated using the .po/.mo translation file system.<br>Enabling this option can improve the page load performance of your site in certain cases. The disadvantage is that you can no longer edit gettext translations using TranslatePress, nor benefit from automatic translation on these strings.'=>'Chuỗi Gettext là các chuỗi được xuất ra bởi theme và plugin. <br> Việc dịch các loại chuỗi này qua TranslatePress có thể không cần thiết nếu chúng đã được dịch bằng hệ thống tệp dịch .po/.mo.<br>Bật tùy chọn này có thể cải thiện hiệu suất tải trang của trang web bạn trong một số trường hợp. Nhược điểm là bạn không thể chỉnh sửa bản dịch gettext bằng TranslatePress nữa, cũng như không được hưởng lợi từ dịch tự động đối với các chuỗi này.','Gettext Strings translation is disabled'=>'Bản dịch chuỗi Gettext đã bị tắt','To enable it go to '=>'Để bật, hãy đi đến ','TranslatePress->Advanced Settings->Debug->Disable translation for gettext strings'=>'TranslatePress->Cài đặt nâng cao->Gỡ lỗi->Tắt dịch cho các chuỗi gettext',' and uncheck the Checkbox.'=>' và bỏ chọn hộp kiểm.','Dismiss'=>'Bỏ qua','Exclude translated links from sitemap'=>'Loại trừ các liên kết đã dịch khỏi sitemap','Do not include translated links in sitemaps generated by SEO plugins.<br/>Requires <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> to be installed and activated.'=>'Không đưa các liên kết đã dịch vào sitemaps được tạo bởi các plugin SEO.<br/>Yêu cầu <a href="https://translatepress.com/docs/addons/seo-pack/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=miscellaneous" title="TranslatePress Add-on SEO Pack documentation" target="_blank"> SEO Pack Add-on</a> được cài đặt và kích hoạt.','Disable post container tags for post title'=>'Tắt thẻ container bài viết cho tiêu đề bài viết','It disables search indexing the post title in translated languages.<br/>Useful when the title of the post doesn\'t allow HTML thus breaking the page.'=>'Tùy chọn này tắt việc lập chỉ mục tìm kiếm tiêu đề bài viết trong các ngôn ngữ đã dịch.<br/>Hữu ích khi tiêu đề bài viết không cho phép HTML, làm hỏng trang.','Disable post container tags for post content'=>'Tắt thẻ container bài viết cho nội dung bài viết','It disables search indexing the post content in translated languages.<br/>Useful when the content of the post doesn\'t allow HTML thus breaking the page.'=>'Tùy chọn này tắt việc lập chỉ mục tìm kiếm nội dung bài viết trong các ngôn ngữ đã dịch.<br/>Hữu ích khi nội dung bài viết không cho phép HTML, làm hỏng trang.','Do not translate certain paths'=>'Không dịch một số đường dẫn nhất định','Choose what paths can be translated. Supports wildcard at the end of the path.<br>For example, to exclude https://example.com/some/path you can either use the rule /some/path/ or /some/*.<br>Enter each rule on it\'s own line. To exclude the home page use {{home}}.'=>'Chọn đường dẫn nào có thể được dịch. Hỗ trợ ký tự đại diện ở cuối đường dẫn.<br>Ví dụ, để loại trừ https://example.com/some/path, bạn có thể sử dụng quy tắc /some/path/ hoặc /some/*.<br>Nhập mỗi quy tắc trên một dòng riêng. Để loại trừ trang chủ, hãy sử dụng {home}.','Exclude Paths From Translation'=>'Loại trừ đường dẫn khỏi bản dịch','Translate Only Certain Paths'=>'Chỉ dịch một số đường dẫn nhất định','Enable the hreflang x-default tag for language:'=>'Bật thẻ hreflang x-default cho ngôn ngữ:','Enables the hreflang="x-default" for an entire language. See documentation for more details.'=>'Bật hreflang="x-default" cho toàn bộ một ngôn ngữ. Xem tài liệu để biết thêm chi tiết.','Translate numbers and numerals'=>'Dịch số và chữ số','Enable translation of numbers ( e.g. phone numbers)'=>'Bật dịch số (ví dụ: số điện thoại)','Selector'=>'Bộ chọn','Exclude from dynamic translation'=>'Loại trừ khỏi dịch động','Do not dynamically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated using JavaScript.<br/>These strings will still be translated on the server side if possible.'=>'Không dịch động các chuỗi nằm trong các nút HTML khớp với các bộ chọn này.<br>Loại trừ tất cả phần tử con của các nút HTML khớp với các bộ chọn này khỏi việc dịch bằng JavaScript.<br/>Các chuỗi này vẫn sẽ được dịch ở phía máy chủ nếu có thể.','Gettext String'=>'Chuỗi Gettext','Exclude Gettext Strings'=>'Loại trừ chuỗi Gettext','Exclude these strings from being translated as Gettext strings by TranslatePress. Leave the domain empty to take into account any Gettext string.<br/>Can still be translated through po/mo files.'=>'Loại trừ các chuỗi này khỏi việc được dịch dưới dạng chuỗi Gettext bởi TranslatePress. Để trống domain để áp dụng cho bất kỳ chuỗi Gettext nào.<br/>Vẫn có thể được dịch qua các tệp po/mo.','Exclude selectors only from automatic translation'=>'Chỉ loại trừ bộ chọn khỏi dịch tự động','Do not automatically translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being automatically translated.<br>Manual translation of these strings is still possible.'=>'Không tự động dịch các chuỗi nằm trong các nút HTML khớp với các bộ chọn này.<br>Loại trừ tất cả phần tử con của các nút HTML khớp với các bộ chọn này khỏi việc được dịch tự động.<br>Việc dịch thủ công các chuỗi này vẫn có thể thực hiện được.','Exclude selectors from translation'=>'Loại trừ bộ chọn khỏi dịch','Do not translate strings that are found in html nodes matching these selectors.<br>Excludes all the children of HTML nodes matching these selectors from being translated.<br>These strings cannot be translated manually nor automatically.'=>'Không dịch các chuỗi nằm trong các nút HTML khớp với các bộ chọn này.<br>Loại trừ tất cả phần tử con của các nút HTML khớp với các bộ chọn này khỏi việc được dịch.<br>Các chuỗi này không thể được dịch thủ công hay tự động.','String'=>'Chuỗi','Exclude strings from automatic translation'=>'Loại trừ chuỗi khỏi dịch tự động','Do not automatically translate these strings (ex. names, technical words...)<br>Paragraphs containing these strings will still be translated except for the specified part.'=>'Không tự động dịch các chuỗi này (ví dụ: tên, thuật ngữ kỹ thuật...)<br>Các đoạn văn chứa các chuỗi này vẫn sẽ được dịch ngoại trừ phần được chỉ định.','Fix broken HTML'=>'Sửa HTML bị hỏng','General attempt to fix broken or missing HTML on translated pages.<br/>'=>'Nỗ lực chung để sửa HTML bị hỏng hoặc thiếu trên các trang đã dịch.<br/>','Force slash at end of home url:'=>'Buộc thêm dấu gạch chéo ở cuối URL trang chủ:','Ads a slash at the end of the home_url() function'=>'Thêm dấu gạch chéo vào cuối hàm home_url()','Show Both (recommended)'=>'Hiển thị cả hai (khuyến nghị)','Remove Country Locale'=>'Xóa locale quốc gia','Remove Region Independent Locale'=>'Xóa locale độc lập khu vực','Remove duplicate hreflang'=>'Xóa hreflang trùng lặp','Choose which hreflang tags will appear on your website.<br/>We recommend showing both types of hreflang tags as indicated by <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">Google documentation</a>.<br/>Removing Country Locale when having multiple Country Locales of the same language (ex. English UK and English US) will result in showing one hreflang tag with link to just one of the region locales for that language.'=>'Chọn thẻ hreflang nào sẽ xuất hiện trên trang web của bạn.<br/>Chúng tôi khuyến nghị hiển thị cả hai loại thẻ hreflang như được chỉ dẫn trong <a href="https://developers.google.com/search/docs/advanced/crawling/localized-versions" title="Google Crawling" target="_blank">tài liệu của Google</a>.<br/>Việc loại bỏ Địa phương quốc gia khi có nhiều Địa phương quốc gia của cùng một ngôn ngữ (ví dụ: English UK và English US) sẽ dẫn đến việc chỉ hiển thị một thẻ hreflang với liên kết đến chỉ một trong các địa phương khu vực của ngôn ngữ đó.','Default (example: en-US, fr-CA, etc.)'=>'Mặc định (ví dụ: en-US, fr-CA, v.v.)','Regional (example: en, fr, es, etc.)'=>'Khu vực (ví dụ: en, fr, es, v.v.)','HTML Lang Attribute Format'=>'Định dạng thuộc tính lang HTML','Change lang attribute of the html tag to a format that includes country regional or not. <br>In HTML, the lang attribute (<html lang="en-US">)  should be used to  specify the language of text content so that the  browser can correctly display or process  your content (eg. for  hyphenation, styling, spell checking, etc).'=>'Thay đổi thuộc tính lang của thẻ html sang định dạng có bao gồm quốc gia/khu vực hoặc không. <br>Trong HTML, thuộc tính lang (<html lang="en-US">) nên được sử dụng để xác định ngôn ngữ của nội dung văn bản để trình duyệt có thể hiển thị hoặc xử lý nội dung của bạn một cách chính xác (ví dụ: để ngắt từ, định dạng, kiểm tra chính tả, v.v.).','Load legacy Language Switcher'=>'Tải bộ chuyển đổi ngôn ngữ cũ','Applies to all types of language switchers (floating, shortcode, and menu). When enabled, the site will revert to using the original Language Switcher configured in the General Settings tab, replacing the new customizable version. Your existing switcher settings will remain saved, but they will be ignored while this option is active.'=>'Áp dụng cho tất cả các loại bộ chuyển đổi ngôn ngữ (nổi, shortcode và menu). Khi bật, trang web sẽ quay lại sử dụng Bộ chuyển đổi ngôn ngữ gốc được cấu hình trong tab Cài đặt chung, thay thế phiên bản tùy chỉnh mới. Các cài đặt bộ chuyển đổi hiện có của bạn sẽ vẫn được lưu, nhưng sẽ bị bỏ qua khi tùy chọn này đang hoạt động.','Load legacy SEO Pack Add-On'=>'Tải tiện ích bổ sung SEO Pack cũ','In case the recent migration to the new slug rewrite is causing trouble, set this to Yes to use the old method <br> Please <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">open a support ticket</a> letting us know of the issues you are having.'=>'Trong trường hợp việc chuyển sang cơ chế viết lại slug mới gần đây gây ra sự cố, hãy đặt tùy chọn này thành Có để sử dụng phương pháp cũ <br> Vui lòng <a href="https://translatepress.com/support/open-ticket/?utm_source=tp-advanced&utm_medium=client-site&utm_campaign=troubleshooting" target="_blank">mở một phiếu hỗ trợ</a> để cho chúng tôi biết về các vấn đề bạn đang gặp phải.','Manual Translation Only'=>'Chỉ dịch thủ công','TranslatePress pro-actively scans and saves strings in the database when users access translated pages. <br>This setting disables this functionality and only allows translation and string saving when inside the Translation Editor. <br>Also disables machine translation outside the Translation Editor, giving you better control over character spending, by translating only the pages you visit in the Translation Editor.'=>'TranslatePress chủ động quét và lưu các chuỗi vào cơ sở dữ liệu khi người dùng truy cập các trang đã dịch. <br>Tùy chọn này tắt chức năng này và chỉ cho phép dịch và lưu chuỗi khi ở trong Trình chỉnh sửa bản dịch. <br>Ngoài ra còn tắt dịch máy bên ngoài Trình chỉnh sửa bản dịch, giúp bạn kiểm soát tốt hơn việc tiêu tốn ký tự, bằng cách chỉ dịch các trang bạn truy cập trong Trình chỉnh sửa bản dịch.','Open language switcher only on click'=>'Chỉ mở bộ chuyển đổi ngôn ngữ khi nhấp chuột','Open the language switcher shortcode by clicking on it instead of hovering.<br> Close it by clicking on it, anywhere else on the screen or by pressing the escape key. This will affect only the shortcode language switcher.'=>'Mở bộ chuyển đổi ngôn ngữ shortcode bằng cách nhấp vào thay vì di chuột qua.<br> Đóng nó bằng cách nhấp vào nó, nhấp vào bất kỳ đâu khác trên màn hình hoặc nhấn phím escape. Điều này chỉ ảnh hưởng đến bộ chuyển đổi ngôn ngữ shortcode.','Show opposite language in the language switcher'=>'Hiển thị ngôn ngữ đối lập trong bộ chuyển đổi ngôn ngữ','Transforms the language switcher into a button showing the other available language, not the current one.<br> Only works when there are exactly two languages, the default one and a translation one.<br>This will affect the shortcode language switcher and floating language switcher as well.<br> To achieve this in menu language switcher go to Appearance->Menus->Language Switcher and select Opposite Language.'=>'Biến bộ chuyển đổi ngôn ngữ thành một nút hiển thị ngôn ngữ khác có sẵn, không phải ngôn ngữ hiện tại.<br> Chỉ hoạt động khi có đúng hai ngôn ngữ, ngôn ngữ mặc định và ngôn ngữ dịch.<br>Điều này sẽ ảnh hưởng đến bộ chuyển đổi ngôn ngữ shortcode và bộ chuyển đổi ngôn ngữ nổi.<br> Để thực hiện điều này trong bộ chuyển đổi ngôn ngữ menu, hãy vào Giao diện->Menu->Bộ chuyển đổi ngôn ngữ và chọn Ngôn ngữ đối lập.','<a href="%s">Click here</a> to access the database optimization tool.'=>'<a href="%s">Nhấp vào đây</a> để truy cập công cụ tối ưu hóa cơ sở dữ liệu.','It helps remove possible duplicate translations, clear unnecessary data and repair possible metadata issues.'=>'Nó giúp loại bỏ các bản dịch trùng lặp có thể có, xóa dữ liệu không cần thiết và sửa chữa các sự cố metadata có thể xảy ra.','<a href="%s" target="_blank">Here</a> you can observe the last 5 SQL errors relevant to TranslatePress if they exist.'=>'<a href="%s" target="_blank">Tại đây</a> bạn có thể xem 5 lỗi SQL cuối cùng liên quan đến TranslatePress nếu có.','Troubleshooting'=>'Khắc phục sự cố','Exclude Gettext strings'=>'Loại trừ chuỗi Gettext','Debug'=>'Gỡ lỗi','Custom languages'=>'Ngôn ngữ tùy chỉnh','Miscellaneous options'=>'Tùy chọn khác','Exclude strings & pages'=>'Loại trừ chuỗi và trang','Automatic Translation Memory'=>'Bộ nhớ dịch tự động','Serve same translation for similar text. The strings need to have a percentage of 95% similarity.<br>Helps prevent losing existing translation when correcting typos or making minor adjustments to the original text. <br>If a translation already exists for a very similar original string, it will automatically be used for the current original string.<br>Does not work when making changes to a text that is part of a translation block unless the new text is manually merged again in a translation block.<br>Each string needs to have a minimum of 50 characters.'=>'Sử dụng chung bản dịch cho văn bản tương tự. Các chuỗi cần có độ tương đồng 95%.<br>Giúp ngăn mất bản dịch hiện có khi sửa lỗi chính tả hoặc điều chỉnh nhỏ văn bản gốc. <br>Nếu đã có bản dịch cho một chuỗi gốc rất tương tự, nó sẽ tự động được sử dụng cho chuỗi gốc hiện tại.<br>Không hoạt động khi thay đổi văn bản thuộc một khối dịch trừ khi văn bản mới được hợp nhất thủ công lại trong khối dịch.<br>Mỗi chuỗi cần có tối thiểu 50 ký tự.','WARNING: This feature can negatively impact page loading times in secondary languages, particularly with large databases (for example websites with a lot of pages or products). If you experience slow loading times, disable this and try again.'=>'CẢNH BÁO: Tính năng này có thể ảnh hưởng tiêu cực đến thời gian tải trang ở ngôn ngữ phụ, đặc biệt với cơ sở dữ liệu lớn (ví dụ các trang web có nhiều trang hoặc sản phẩm). Nếu bạn gặp tình trạng tải chậm, hãy tắt tính năng này và thử lại.','Fix missing dynamic content'=>'Sửa nội dung động bị thiếu','May help fix missing content inserted using JavaScript. <br> It shows dynamically inserted content in original language for a moment before the translation request is finished.'=>'Có thể giúp sửa nội dung bị thiếu được chèn bằng JavaScript. <br> Nó hiển thị nội dung được chèn động bằng ngôn ngữ gốc trong giây lát trước khi yêu cầu dịch hoàn tất.','Filter Gettext wrapping from post content and title'=>'Lọc bọc Gettext khỏi nội dung và tiêu đề bài viết','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post content and post title. Does not affect previous post content. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Lọc bọc Gettext như #!trpst#trp-gettext khỏi toàn bộ nội dung và tiêu đề bài viết đã cập nhật. Không ảnh hưởng đến nội dung bài viết trước đó. <br/><strong>Nên sao lưu cơ sở dữ liệu trước khi bật.</strong>','Filter Gettext wrapping from post meta'=>'Lọc bọc Gettext khỏi meta bài viết','Filters gettext wrapping such as #!trpst#trp-gettext from all updated post meta. Does not affect previous post meta. <br/><strong>Database backup is recommended before switching on.</strong>'=>'Lọc bọc Gettext như #!trpst#trp-gettext khỏi toàn bộ meta bài viết đã cập nhật. Không ảnh hưởng đến meta bài viết trước đó. <br/><strong>Nên sao lưu cơ sở dữ liệu trước khi bật.</strong>','Google Translate v2'=>'Google Translate v2','Google Translate API Key'=>'Khóa API Google Translate','Add your API Key here...'=>'Thêm khóa API của bạn vào đây...','Visit <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">this link</a> to see how you can set up an API key, <strong>control API costs</strong> and set HTTP referrer restrictions.'=>'Truy cập <a href="https://cloud.google.com/docs/authentication/api-keys" target="_blank">liên kết này</a> để xem cách thiết lập khóa API, <strong>kiểm soát chi phí API</strong> và đặt các hạn chế về HTTP referrer.','Your HTTP referrer is: %s'=>'HTTP referrer của bạn là: %s','There was an error on the server processing your Google Translate key.'=>'Đã xảy ra lỗi trên máy chủ khi xử lý khóa Google Translate của bạn.','There was an error with your Google Translate key.'=>'Đã xảy ra lỗi với khóa Google Translate của bạn.','Please check your TranslatePress license key.'=>'Vui lòng kiểm tra khóa cấp phép TranslatePress của bạn.','TranslatePress AI'=>'TranslatePress AI','No Active License Detected for this website.'=>'Không phát hiện khóa cấp phép đang hoạt động cho trang web này.','In order to enable Automatic Translation using TranslatePress AI, you need a license key by creating a free account.'=>'Để kích hoạt Dịch tự động bằng TranslatePress AI, bạn cần có khóa cấp phép bằng cách tạo một tài khoản miễn phí.','Create your Free Account'=>'Tạo tài khoản miễn phí',' or '=>' hoặc ','Enter your license key'=>'Nhập khóa bản quyền của bạn',' Or %1$spurchase one here%2$s'=>' Hoặc %1$smua tại đây%2$s','Your free account includes: '=>'Tài khoản miễn phí của bạn bao gồm: ','Get more AI Words and unlock all AI features with TranslatePress Pro.'=>'Nhận thêm từ AI và mở khóa tất cả tính năng AI với TranslatePress Pro.','You have a valid %s <strong>license</strong>.'=>'Bạn có <strong>bản quyền</strong> %s hợp lệ.',' words remaining. '=>' từ còn lại. ','Recheck'=>'Kiểm tra lại','Rechecking...'=>'Đang kiểm tra lại...','Done.'=>'Xong.','Manage your license & quota on the %s'=>'Quản lý bản quyền & hạn mức của bạn trên %s','TranslatePress.com Account Page'=>'Trang Tài khoản TranslatePress.com','SEO support for page slug, page title, description and Facebook and Twitter social graph information. The HTML lang attribute is properly set.'=>'Hỗ trợ SEO cho slug trang, tiêu đề trang, mô tả và thông tin đồ thị mạng xã hội Facebook và Twitter. Thuộc tính lang HTML được thiết lập đúng cách.','Enable Modules'=>'Bật mô-đun','Enable Add-on modules to extend TranslatePress and enhance the functionality of your translated site.'=>'Bật các mô-đun bổ sung để mở rộng TranslatePress và nâng cao chức năng cho trang web đã dịch của bạn.','More functionality with TranslatePress Pro.'=>'Nhiều chức năng hơn với TranslatePress Pro.','Already a Pro User?'=>'Đã là người dùng Pro?','Activate License Key'=>'Kích hoạt khóa bản quyền','This add-on is not available on your current plan.'=>'Tiện ích bổ sung này không khả dụng trong gói hiện tại của bạn.','Continue'=>'Tiếp tục','The link you followed has expired. Please reload the page and try again.'=>'Liên kết bạn đã theo dõi đã hết hạn. Vui lòng tải lại trang và thử lại.','A valid license is required to enable Automatic Translation.'=>'Cần có giấy phép hợp lệ để kích hoạt Dịch Tự động.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Manage Sites.'=>'Khóa giấy phép của bạn đã bị vô hiệu hóa cho URL này. Hãy kích hoạt lại từ <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=tp-ai">https://translatepress.com/account</a> -> Quản lý trang web.','<p><strong>License key mismatch.</strong> The license you entered doesn\'t match the TranslatePress version you have installed.</p><p>Please check that you\'ve installed the correct version for your license from your TranslatePress account.</p>'=>'<p><strong>Khóa giấy phép không khớp.</strong> Giấy phép bạn đã nhập không khớp với phiên bản TranslatePress đã cài đặt.</p><p>Vui lòng kiểm tra rằng bạn đã cài đặt đúng phiên bản cho giấy phép của mình từ tài khoản TranslatePress của bạn.</p>','Automatically translate your website using TranslatePress AI.'=>'Tự động dịch trang web của bạn bằng TranslatePress AI.','In order to enable Automatic Translation using TranslatePress AI, please enter your license key from'=>'Để kích hoạt Dịch Tự động bằng TranslatePress AI, vui lòng nhập khóa giấy phép của bạn từ','your account.'=>'tài khoản của bạn.','Skip and continue with manual translation »'=>'Bỏ qua và tiếp tục với bản dịch thủ công »','Get Your Free TranslatePress AI License'=>'Nhận giấy phép TranslatePress AI miễn phí của bạn','Generate License'=>'Tạo giấy phép','Creating a free account includes: '=>'Việc tạo tài khoản miễn phí bao gồm: ','Are you a TranslatePress PRO user?'=>'Bạn có phải là người dùng TranslatePress PRO không?','Install & Activate your pro plugin.'=>'Cài đặt & kích hoạt plugin pro của bạn.','Skip this step'=>'Bỏ qua bước này','The email address you added is incorrect.'=>'Địa chỉ email bạn đã thêm không chính xác.','Setup Complete'=>'Thiết lập hoàn tất','You\'re ready to start translating!'=>'Bạn đã sẵn sàng bắt đầu dịch!','You have successfully set up TranslatePress for your website.'=>'Bạn đã thiết lập thành công TranslatePress cho trang web của mình.','Receive '=>'Nhận ','Yes, send me multilingual growth tips.'=>'Có, hãy gửi cho tôi các mẹo phát triển đa ngôn ngữ.','Start translating'=>'Bắt đầu dịch','Sign Up and Start translating'=>'Đăng ký và bắt đầu dịch','Please upload a TranslatePress Pro plugin file.'=>'Vui lòng tải lên tệp plugin TranslatePress Pro.','Upload error: '=>'Lỗi tải lên: ','Install failed: '=>'Cài đặt thất bại: ','Plugin installed, but entry file not found. '=>'Plugin đã được cài đặt, nhưng không tìm thấy tệp chính. ','Activation error: '=>'Lỗi kích hoạt: ','Invalid plugin specified.'=>'Plugin được chỉ định không hợp lệ.','Invalid action specified.'=>'Hành động được chỉ định không hợp lệ.','Plugin deactivation failed.'=>'Không thể hủy kích hoạt plugin.','Plugin activation failed: '=>'Không thể kích hoạt plugin: ','First, install and activate TranslatePress Pro'=>'Trước tiên, hãy cài đặt và kích hoạt TranslatePress Pro','Please upload the TranslatePress PRO zip archive from your'=>'Vui lòng tải lên tệp nén zip TranslatePress Pro từ','TranslatePress Account'=>'TranslatePress Account','Install and Activate'=>'Cài đặt và kích hoạt','Installed Pro versions'=>'Các phiên bản Pro đã cài đặt','« Go back'=>'« Quay lại','Activate License »'=>'Kích hoạt giấy phép »','You are trying to add an invalid additional language. Please select a valid option.'=>'Bạn đang cố thêm một ngôn ngữ bổ sung không hợp lệ. Vui lòng chọn một tùy chọn hợp lệ.','Please add an additional language.'=>'Vui lòng thêm ngôn ngữ bổ sung.','You are trying to add an invalid default language. Please select a valid option.'=>'Bạn đang thử thêm ngôn ngữ mặc định không hợp lệ. Vui lòng chọn tùy chọn hợp lệ.','You need to select a default language.'=>'Bạn cần chọn ngôn ngữ mặc định.','Configure Site Languages'=>'Cấu hình ngôn ngữ trang web','Select the default and additional languages for your website.'=>'Chọn ngôn ngữ mặc định và ngôn ngữ bổ sung cho trang web của bạn.','You can edit your site languages at any point.'=>'Bạn có thể chỉnh sửa ngôn ngữ trang web bất cứ lúc nào.','Additional Language'=>'Ngôn ngữ bổ sung','Choose a secondary language...'=>'Chọn ngôn ngữ phụ...','Add Language'=>'Thêm ngôn ngữ','Choose a language...'=>'Chọn ngôn ngữ...','Add more than two languages with TranslatePress Pro.'=>'Thêm hơn hai ngôn ngữ với TranslatePress Pro.','Your license key is disabled for this URL. Re-enable it from <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Manage Sites.'=>'Khóa giấy phép của bạn đã bị vô hiệu hóa cho URL này. Hãy kích hoạt lại từ <a target="_blank" href="https://translatepress.com/account/?utm_source=tp-onboarding&utm_medium=client-site&utm_campaign=activate-license">https://translatepress.com/account</a> -> Quản lý các site.','Add your License Key'=>'Thêm khóa giấy phép của bạn','Add your License Key to unlock all premium features. Find the License Key in your'=>'Thêm khóa giấy phép của bạn để mở khóa tất cả các tính năng cao cấp. Tìm khóa giấy phép trong','Your license is valid and active.'=>'Giấy phép của bạn hợp lệ và đang hoạt động.','« Go Back'=>'« Quay lại','Set up Language Switcher'=>'Thiết lập bộ chuyển đổi ngôn ngữ','Select the style of the language switcher. You will find more ways to display it, in plugin settings.'=>'Chọn kiểu của bộ chuyển đổi ngôn ngữ. Bạn sẽ tìm thấy thêm nhiều cách hiển thị trong cài đặt plugin.','Displays a small language drop-down across your website, in a corner of your choosing.'=>'Hiển thị menu thả xuống ngôn ngữ nhỏ trên khắp trang web của bạn, tại góc mà bạn chọn.','Switcher Location'=>'Vị trí bộ chuyển đổi ngôn ngữ','Apply a Template'=>'Áp dụng mẫu','You can customize the design later'=>'Bạn có thể tùy chỉnh thiết kế sau','Default Template'=>'Mẫu mặc định','Dark Template'=>'Mẫu tối','Border Template'=>'Mẫu viền','Border'=>'Viền','Transparent Template'=>'Mẫu trong suốt','Transparent'=>'Trong suốt','Welcome to TranslatePress'=>'Chào mừng bạn đến với TranslatePress','Quick guided setup to configure TranslatePress in no time!'=>'Hướng dẫn thiết lập nhanh để cấu hình TranslatePress chỉ trong giây lát!','It takes less than a minute.'=>'Chỉ mất chưa đầy một phút.','Scanning item %1$d of %2$d...'=>'Đang quét mục %1$d trên %2$d...','Manually translated'=>'Đã dịch thủ công','Automatically translated'=>'Đã dịch tự động','Not translated'=>'Chưa dịch','Bulk Actions'=>'Thao tác hàng loạt','Delete entries'=>'Xóa các mục','Edit'=>'Sửa','Delete'=>'Xóa','Filter'=>'Lọc','Clear filters'=>'Xóa bộ lọc','Add New'=>'Thêm mới','Rescan plugins and theme for strings'=>'Quét lại plugin và giao diện để tìm chuỗi','Scanning plugins and theme for strings...'=>'Đang quét plugin và giao diện để tìm chuỗi...','Plugins and theme scan is complete'=>'Đã quét xong plugin và giao diện','Plugins and theme scan did not finish due to an error'=>'Quét plugin và giao diện không hoàn tất do lỗi','Import / Export'=>'Nhập / Xuất','items'=>'mục','See More'=>'Xem thêm','See Less'=>'Xem ít hơn','Apply'=>'Áp dụng','No strings match your query.'=>'Không có chuỗi nào khớp với truy vấn của bạn.','Try to rescan plugins and theme for strings.'=>'Thử quét lại plugin và giao diện để tìm chuỗi.','An error occurred while loading results. Most likely you were logged out. Reload page?'=>'Đã xảy ra lỗi khi tải kết quả. Có thể bạn đã bị đăng xuất. Tải lại trang?','found in translation'=>'tìm thấy trong bản dịch','Select All'=>'Chọn tất cả','Select Visible'=>'Chọn các mục hiển thị','You are about to perform this action on all the strings matching your filter, not just the visibly checked. To perform the action only to the visible strings click "Select Visible" from the table header dropdown.'=>'Bạn sắp thực hiện thao tác này trên tất cả các chuỗi khớp với bộ lọc, không chỉ những chuỗi hiển thị đã được chọn. Để chỉ thực 